campAnduin = "Den Anduin hinab",
campAnduinInfo = "Noch immer mit einer Nachricht von König Thranduil an Herrin Galadriel im Gepäck verlasst ihr den Düsterwald. Euer Plan, mit dem Floß entlang des Anduin nach Süden zu fahren, wird durchkreuzt.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Waldelben\nRegion: Anduin, Dol Guldur",
campAruwethil = "Die Unterstadt",
campAruwethilInfo = "Ihr habt das Ritual der Bergmenschen aufgehalten und die schreckliche Apparatur zerstört. Doch die mysteriöse Frau muss noch irgendwo sein. Ihr ahnt, welche Gefahr von ihr ausgeht, und beschließt, sie in der Stadt unter Fornosts Ruinen aufzuspüren und zu vernichten. Möge die Jagd beginnen!\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Hobbits, Dúnedain\nRegion: Fornost",
campBarrowDowns = "Ärger in den Hügelgräberhöhen",
campBarrowDownsInfo = "Eure Nachforschungen haben ergeben, dass eine größere Geschichte hinter dem Aufruhr in Bree steckt. Ihr verfolgt eine Spur in die berüchtigten Hügelgräberhöhen. Im dichten Nebel sucht ihr nach weiteren Anzeichen bösartiger Machenschaften\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Dúnedain\nRegion: Hügelgräberhöhen",
campBreeMurder = "Mord und Totschlag",
campBreeMurderInfo = "Ein entsetzlicher Mord erschüttert das friedliche Dorf Bree. Wer könnte hinter dieser schändlichen Tat stecken … und was ist das Motiv?\n\nSchwierigkeit: Leicht\nEmpfohlene Charaktere: Hobbits, Dúnedain\nRegion: Bree",
campBreeTrouble = "Aufruhr in Bree",
campBreeTroubleInfo = "In Bree herrscht große Aufregung. Banditen lauern in den Schatten und rauben ungestraft. Die ängstlichen Bewohner warten sehnsüchtig auf jemanden, der sie von dem Gesindel befreit.\n\nSchwierigkeit: Leicht\nEmpfohlene Charaktere: Hobbits, Dúnedain\nRegion: Bree",
campCairAndros = "Belagerung von Cair Andros",
campCairAndrosInfo = "In Ithilien erreicht euch eine dringende Nachricht: Der Feind hat Truppen zusammenzogen und versucht einen Sturm auf Cair Andros. Die befestigte Insel im Anduin dient als Bollwerk Gondors gegen die Gefahr aus dem Osten und darf auf keinen Fall in feindliche Hände fallen. Du beschließt sofort, mit deinen Gefährten den Verteidigern Gondors zu Hilfe zu eilen.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Gondor\nRegion: Cair Andros",
campCarnDum = "Angriff auf Carn Dûm",
campCarnDumInfo = "Ihr habt es erfolgreich zurück nach Bruchtal geschafft, wo Elrond sogleich eine Besprechung abhalten lässt. Es ist ohne Zweifel, dass das Böse im Norden erstarkt ist und das Vermächtnis Angmars mit neuem, verdorbenem Leben füllen möchte. Nur eine entschlossene Maßnahme kann das erneute Erwachen Angmars verhindern.\nViel deutet darauf hin, dass die Quelle der erstarkten feindlichen Macht in der Festung Carn Dûm zu suchen ist, dem einstigen Sitz des Hexenkönigs von Angmar. Während Aragorn die kampfbereiten Dúnedain nach Bruchtal ruft, stellt Elrond eine kleine Armee zusammen. Mit vereinten Kräften wird es hoffentlich möglich sein, die Verderbnis wieder aus Eriador zu vertreiben.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Dúnedain, Noldor\nRegion: Carn Dûm",
campCarrock = "Über den Hohen Pass",
campCarrockInfo = "Du brichst mit deiner Gruppe von Reisegefährten in Bruchtal auf, um Beorn auf der anderen Seite des Nebelgebirges zu besuchen. Auf dem Weg werdet ihr schon bald von winterlichem Wetter überrascht. Während ihr euch durch den Schnee kämpft, wittern Orks und Wölfe frische Beute.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Noldor\nRegion: Nebelgebirge",
campChetwald = "Breeland in Gefahr",
campChetwaldInfo = "Ihr erholt euch im Hause Elronds von euren Abenteuern, als ein Bote für Aragorn eintrifft. Der Dúnedain berichtet von einer großen Schar Orks, die westlich der Wetterberge beobachtet worden sein.\n'So viele haben wir schon lange nicht mehr so weit im Westen gesehen. Sie spähen das Land aus und wir fürchten, sie könnten die Siedlungen in Breeland überfallen.\nDu wirfst einen kurzen Blick auf deine Gefährten und siehst in entschlossene Gesichter. 'Anscheinend ist die Zeit der Rast vorbei. Wir werden den Dúnedain beistehen und die Orks von Breeland fernhalten.'\nNoch am selbigen Tag brecht ihr auf gen Westen.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Dúnedain\nRegion: Chetwald, Wetterberge",
campConspiracy = "Verschwörung in Minas Tirith",
campConspiracyInfo = "Auf Einladung des Truchsessen von Gondor triffst du mit deiner Gemeinschaft in Minas Tirith, der Weißen Stadt ein. Wie du erfährst, macht sich der Statthalter Sorgen über verdächtige Aktivitäten in der Stadt. Dabei hat Gondor genügend Feinde außerhalb der Stadtmauern. Du willigst ein, einer möglichen Verschwörung nachzugehen.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Gondor\nRegion: Minas Tirith",
campDefeat = "Du bist gescheitert, weil du die Kampagnenaufgaben nicht erfüllen konntest.",
campDolGuldur = "Inspektion von Dol Guldur",
campDolGuldurInfo = "Nach deiner Reise durch den Düsterwald steht eines fest: Um die alte Festung Dol Guldur herum geht Dunkles vor sich. Nach einigen Überlegungen bittet dich die Herrin Galadriel, die dunkle Festung zu untersuchen und herauszufinden, was oder wer dort sein Unwesen treibt.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: beliebig\nRegion: Düsterwald, Dol Guldur",
campDruadan = "Durch den Drúadan-Wald",
campDruadanInfo = "Nach der teuren, aber erfolgreichen Verteidigung von Cair Andros geht es nun darum, die versprengten Feinde zu jagen. Ihr folgt einer Schar Orks, die sich westwärts ins Landesinnere Gondors bewegen. Ihr müsst sie aufhalten, ehe sie über das Hinterland herfallen können. Doch als ihre Spur schließlich in den Drúadan-Wald führt, kommen euch Zweifel…\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Gondor\nRegion: Drúadan-Wald",
campDunlandperlen = "Kein Freihandel in Dunland",
campDunlandperlenInfo = "Auf dem Weg von Rohan nach Bruchtal begegnet ihr auf einer einsamen Straße einer verzweifelten Frau. Ihre Augen sind von Tränen gerötet, und ihre Stimme ist voller Angst, als sie euch von ihrer misslichen Lage erzählt. Ihr Ehemann, ein wohlhabender Händler, wurde von den Dunländern gefangen genommen. Sie fleht euch an, ihn zu retten und ihn sicher zu ihr zurückzubringen.\n\nIhr erfahrt, dass der Händler von den Dunländern während eines Überfalls auf seinem Handelsweg gefangen genommen wurde. Der Streit zwischen den Dunländern und den Rohirrim ist brisant, und die gefährlichen Wegstrecken sind voller Feinde. Eure Hilfe wird dringend benötigt, denn der Händler befindet sich in einem geheimen Lager tief im Land der Dunländer.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Rohirrim\nRegion: Dunland",
campDunlandwolves = "Der Blutpakt",
campDunlandwolvesInfo = "Die Nachricht eurer Flucht aus Dunland hat den Wolfsclan in Raserei versetzt. Nun stürmen die Dunländer in Scharen auf die Furt des Isen zu, entschlossen, nach Rohan vorzudringen. Ihr müsst euch ihnen entgegenstellen, Seite an Seite mit den tapferen Rohirrim, um die Flut dieser wilden Krieger aufzuhalten. Die Verteidigung der Furt ist entscheidend, denn wenn sie fällt, ist der Weg nach Rohan offen. Ihr wisst, dass ihr durchhalten müsst, bis Verstärkung eintrifft – oder bis der letzte Feind besiegt ist. Als ihr euch zur Verteidigung bereit macht, erfüllt ein grausiges Heulen die Luft. Offenbar hat der Wolfsclan einen Pakt mit den Wargen des Nebelgebirges geschlossen.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Rohirrim\nRegion: Rohan, Dunland",
campDurinsBane = "Durins Fluch",
campDurinsBaneInfo = "Ihr seid in die östlichen Minen Morias vorgedrungen und sucht nach dem Ausgang. Noch wisst ihr nicht, dass euch in den Tiefen weitaus Schrecklicheres erwartet als Scharen von Orks.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Zwerge\nRegion: Moria",
campEdoras = "Die Waffen des Königs",
campEdorasInfo = "Ihr seid soeben in Edoras eingetroffen, um dem König von Rohan eure Dienste anzubieten, da bricht ein Aufruhr in der Stadt aus. Offenbar hatte es einen Einbruch in die Waffenkammer gegeben und unter den gestohlenen Waffen soll sich auch das königliche Schwert Herugrim befinden. Niemand würde einem Einheimischen ein derart dreistes Verbrechen zutrauen, daher fällt der Verdacht kurzerhand auf euch. Ihr hättet zu keinem ungünstigeren Zeitpunkt eintreffen können, doch immerhin ist der König nicht von eurer Schuld überzeugt. Um eure eigene Haut zu retten, versprecht ihr, bei der Aufklärung des Diebstahls zu helfen.\n\nSchwierigkeit: Leicht\nEmpfohlene Charaktere: Rohan\nRegion: Rohan, Edoras",
campErebor = "Das Herz des Erebor",
campEreborInfo = "Nach Jahren des Friedens und des Wiederaufbaus im Erebor unter König Dáin Eisenfuß beginnt das zwergische Reich erneut zu erblühen. Doch tief im Inneren des Einsamen Berges stoßen die Zwerge auf seltsame Geräusche und verschwundene Arbeiter. Gerüchte über uralte Kreaturen, die in den vergessenen Tiefen hausen, verbreiten Angst unter den Minenarbeitern. Der König ruft tapfere Abenteurer zusammen, um eine Expedition in die unerforschten Tiefen zu führen, die neuen Minen zu sichern und herauszufinden, welche uralten Bedrohungen wieder aufgetaucht sind. Es ist eure Aufgabe, dem Ruf zu folgen und den Erebor von den dunklen Kreaturen der Tiefe zu befreien.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Zwerge\nRegion: Erebor",
campEscapeDolGuldur = "Flucht aus Dol Guldur",
campEscapeDolGuldurInfo = "In Dol Guldur ist deine Gruppe in eine Falle geraten und wurde in eine Folterkammer trief im Innern der Festung verschleppt. Versuche, dich zu befreien und einen Weg aus der Festung heraus zu finden.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: beliebig\nRegion: Dol Guldur",
campEttenmoors = "Durch die Ettenöden",
campEttenmoorsInfo = "Eure Gruppe ist aus der Gefangenschaft in Berg Gram entkommen. Zwar ist es euch gelungen, eure Verfolger abzuschütteln, doch nun steht euch der beschwerliche Weg durch die Wildnis der Ettenöden bevor. Orks, Warge, Wildmenschen, und Trolle streunen dort umher und es wird schwierig werden, ungesehen bis nach Bruchtal zu gelangen.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Beliebig\nRegion: Ettenöden",
campFangorn = "In Fangorns Fängen",
campFangornInfo = "Das Orkheer in den Ödlanden ist vernichtend geschlagen, doch die Überreste der Streitmacht fliehen vor den tödlichen Lanzen der Rohirrim. Ihr verfolgt eine Gruppe flüchtender Orks Richtung Nordwesten, wo sie der Wahnsinn in den Fangorn hineintreibt. Einen Moment zögert ihr, dann nehmt ihr die Verfolgung auf.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Ents\nRegion: Fangorn",
campFornost = "Unruhe in Fornost",
campFornostInfo = "In den Notizen der Grabräuber bei den Hügelgräberhöhen findet ihr einen Hinweis, dass ihr eigentlicher Auftraggeber sich in Fornost aufhält und dort geheimen Machenschaften nachgeht. Also begebt ihr euch auf der Straße nordwärts nach Fornost Erain, im Auenland und von den Breeländern auch Totendeich genannt. Die Führung übernimmt Beravor, die sich in der Gegend auskennt wie kaum ein anderer.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Hobbits, Dúnedain\nRegion: Fornost",
campFoundationsOfStone = "Grundfesten aus Stein",
campFoundationsOfStoneInfo = "Auf der Flucht vor den Orks habt ihr euch in den Tiefen Morias verirrt. Nicht wissend, welcher Weg zurück ans Tageslicht führt, folgt ihr dem dumpfen Rauschen eines unterirdischen Flusses in der Hoffnung, er möge euch zum Ausgang bringen.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Zwerge, Noldor\nRegion: Moria",
campFramsburg = "Der Geist von Framsburg",
campFramsburgInfo = "Framsburg war einst eine Stadt der Éothéod, wie man die Rohirrim nannte, ehe sie ins heutige Rohan gezogen waren. Durch Beorn erfahrt ihr von der Legende, wie ihr Namensgeber Fram den Drachen Scatha erschlagen hatte. Sein mächtiges Schwert soll mit ihm in einer Gruft unter der Stadt ruhen. Framsburg ist jedoch schon seit hunderten von Jahren verfallen. Die Abenteuerlust brennt stark in euch, darum beschließt ihr das tollkühne Unterfangen, das Schwert von Fram zu bergen.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Thal\nRegion: Framsburg",
campGollum = "Die Jagd nach Gollum",
campGollumInfo = "Ihr sitzt gerade mit Beorn in der großen Halle zusammen und erzählt euch Geschichten aus alter Zeit, da klopft es plötzlich an der Tür. Als du öffnest, erblickst du einen bärtigen Mann mit grauem Mantel und spitzem Hut. Erstaunt fragst du, was Gandalf den Grauen ausgerechnet jetzt in diese Gegend geführt hat.\n'Das Geschöpft Gollum', antwortete der Zauberer. Er erklärte, dass die Kreatur in der Gegend gesichtet wurde und er sich nur zu gerne mit ihr unterhalten würde. Du verzichtest auf Rücksprache mit deinen Gefährten und bietest umgehend deine Hilfe an.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Dúnedain\nRegion: Düsterwald",
campGram = "Flucht von Berg Gram",
campGramInfo = "Nach eurer Flucht vor den Wölfen wart ihr erschöpft und ausgelaugt. Somit konntet ihr keine Gegenwehr leisten, als ihr auf eine weitere Gruppe Orks stießt.\n\nEuer Glück im Unglück: Wie schon die unschuldigen Zivilisten zuvor wurdet auch ihr nicht von den Orks getötet, sondern stattdessen gefesselt und fortgeschleppt. Auf einem langen Marsch in Ketten brachten sie euch in die Verliese von Berg Gram. Dort erwartet ihr nun, jeder in einer eigenen Zelle, das drohende Schicksal. Wenn überhaupt galt eure einzige Hoffnung Amarthiúl, der die Wölfe abgelenkt hatte und daher nicht mit euch in die Arme der Orks gelaufen war.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Dúnedain\nRegion: Berg Gram",
campIthilien = "Auftrag in Ithilien",
campIthilienInfo = "Nachdem ihr die Verschwörung in Minas Tirith aufgedeckt und beseitigt hat, informiert euch der Truchsess über die Bedrohung an den Außengrenzen des Landes. Korsaren bedrohen die Südküste und fahren durch die Mündung des Anduin bis nach Pelargir, Orktrupps sind in der Umgebung von Cair Andros im Norden gesehen worden und Saurons Verbündete aus dem Süden ziehen durch Ithilien nach Mordor.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Gondor, Dúnedain\nRegion: Ithilien",
campKidnapping = "Die Entführung",
campKidnappingInfo = "Du bist zu Besuch bei Beorn und genießt mit deinen Freunden dessen zuvorkommende Gastwirtschaft. Am Morgen nach einer durchzechten Nacht voller Honigmet machst du jedoch eine beunruhigende Entdeckung: Einer deiner Gefährten ist spurlos verschwunden! Was ist geschehen? Niemand hat etwas bemerkt. Zu allem Überfluss ist auch Beorn nicht zuhause. Also musst du dich aufmachen, deinen Gefährten wiederzufinden.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Beliebig\nRegion: Beorns Halle, Düsterwald",
campLongDark = "Die lange Dunkelheit",
campLongDarkInfo = "Eure Gruppe beschließt, die Minen von Moria zu erkunden. Zuerst müsst ihr die Zwergentür finden und das Losungswort sprechen. Dahinter wartet euch eine tiefe Dunkelheit und verzweigte Gänge, durch die ihr endlos wandern könnt, wenn ihr falsch abbiegt.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Zwerge, Noldor\nRegion: Moria, Nebelgebirge",
campMirkwood = "Reise durch den Düsterwald",
campMirkwoodInfo = "Ihr sollt eine dringende Nachricht von König Thranduil zu Königin Galadriel überbringen. Eure Reise führt euch durch den Düsterwald, wo sich in letzter Zeit Dunkelheit ausgebreitet hat.\n\nSchwierigkeit: Einfach\nEmpfohlene Charaktere: Waldelben\nRegion: Düsterwald",
campOldFord = "Reise den Anduin hinauf",
campOldFordInfo = "Nachdem ihr Gandalf nach Lothlórien begleitet habt, wo Gollum verhört werden soll, reist du mit deiner Gefährtenschaft am Anduin entlang nordwärts, um zu Beorns Halle zurückzukehren. An der Alten Furt, die von den Beorningern bewacht wird, wollt ihr den Fluss überqueren. Unterwegs kommt ihr an einigen kleinen Siedlungen der Waldmenschen vorbei. Gefahr zieht herauf, als ihr einen Warg-Reiter auf einem nahegelegenen Hügel erblickt. Ein Späher vielleicht?\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Beliebig\nRegion: Anduin",
campOsgiliath = "Schlacht um Osgiliath",
campOsgiliathInfo = "Nach der Schlacht um Cair Andros und der anschließenden Jagd auf die versprengten Feinde im Landesinneren kehrt ihr zurück nach Minas Tirith, wo zur Feier des Sieges ein rauschendes Fest gefeiert wird. Doch am nächsten Morgen, ehe ihr den Rausch ausgeschlafen habt, lässt euch der Statthalter wecken. Ein Bote ist mit einer dringenden Botschaft eingetroffen: Der Feind zieht mit einer weiteren Streitmacht gegen Osgiliath und wird die Stadt in wenigen Tagen erreichen.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Gondor\nRegion: Osgiliath",
campOstmark = "Schild der Ostfold",
campOstmarkInfo = "Ihr seid eben in den Dienst Rohans getreten und habt Euren den Eid dem König geschworen, das Land vor seinen Feinden zu schützen, da treffen schlimme Nachrichten in Edoras ein. Orks haben das Ödland durchstreift und sind in die Ostfold eingefallen, die Grenzwächter wurden überrannt und Dörfer stehen in Flammen. König Théoden lässt umgehend eine Schar Reiter zusammenstellen und trägt euch auf, bei der Verteidigung der Ostfold zu helfen.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Rohan\nRegion: Rohan, Ents",
campRedhornGate = "Der Rothornpass",
campRedhornGateInfo = "Celeborn hat euch gebeten, Arwen, die ihren Vater in Bruchtal besuchen will, zu begleiten. Euer Weg führt euch über den Rothornpass, auf dem mancherlei Gefahren lauern.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Noldor\nRegionen: Nebelgebirge, Rothornpass",
campRivendell = "Der Weg nach Bruchtal",
campRivendellInfo = "Eure Gruppe hat den Rothornpass überwunden. Nun müsst ihr euch nordwärts wenden und die Straße entlang des Nebelgebirges nach Bruchtal nehmen, um Arwen nach Hause zu bringen.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Noldor, Dúnedain\nRegionen: Nebelgebirge, Eriador",
campThaudir = "Die Toten erwachen",
campThaudirInfo = "Nach der Erstürmung des Orklagers in den Wetterbergen fandet ihr die Leichen mehrerer Männer und Frauen, die vermutlich für irgendein bösartiges Ritual geopfert worden waren, sowie ein paar verwirrte Überlebende. Dies mehrt die Sorge der Dúnedain über die ohnehin schon merkwürdigen Aktionen der Orks. Nach kurzer Besprechung beschließt ihr, mit den Dúnedain und den Überlebenden nach Fornost Erain zu gehen, wo eine große Versammlung der Waldläufer zur Feier der Herbsttagundnachtgleiche stattfindet.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Dúnedain\nRegion: Fornost",
campThreeClans = "Schatten über Dunland",
campThreeClansInfo = "Nach der Beendigung des Blutpaktes erhaltet ihr eine unerwartete Einladung nach Isengart, wo Saruman der Weiße euch erwartet. In seiner Weisheit zeigt er sich  besorgt über die Unruhen in den wilden Landen der Dunländer. Saruman hat einen unheilvollen Verdacht: Eine dunkle Macht, zu der sich Saruman nicht näher äußern möchte, könnte die Clans aufstacheln und manipulieren. Diese Bedrohung müsst ihr aufdecken und neutralisieren, bevor sie zu einem Feuer heranwächst, das den Frieden in Mittelerde gefährdet. Um dies zu erreichen, müsst ihr die zerstrittenen Clans der Dunländer befrieden und ihre alten Streitigkeiten beilegen. Eure Reise wird euch an die Grenzen des Bekannten führen, wo alte Geheimnisse und neue Gefahren lauern.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Rohirrim\nRegion: Dunland",
campVictory = "Du hast gewonnen, indem du die Siegbedingung der Kampagne erfüllt hast.",
campWatcher = "Der Wächter im Wasser",
campWatcherInfo = "Ihr habt Arwen erfolgreich nach Bruchtal begleitet. Elrond hat euch gebeten, bei eurer Rückkehr nach Lórien die Minen Morias auszukundschaften, um herauszufinden, ob sie der Ursprung der verstärkten Ork-Aktivitäten in jüngster Zeit sind.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Noldor, Zwerge\nRegionen: Eriador, Nebelgebirge",
campWolfWastes = "Die Ödlande von Eriador",
campWolfWastesInfo = "Die Schlacht um Fornost wurde heftig und erbittert geführt. Ohne die Hilfe der Helden hätten sich die Dúnedain vermutlich zurückziehen müssen. Letztlich erlitten sie viele Wunden, konnten jedoch die Untoten zurückschlagen und sie in der Unterstadt einsperren. Doch der böse Geist, der die Untoten mutmaßlich erweckt hat, konnte mit einigen Schergen entkommen. Mehr noch, einer der Waldläufer behauptet gesehen zu haben, wie sie Iâron überwältigt und mit sich genommen haben. Nach den jüngsten Entdeckungen wollt ihr euch nicht ausmalen, welches Schicksal ihm droht. Während die Dúnedain alle Kräfte benötigen, um den Totendeich zu sichern, heftet ihr euch erneut den Entführern an die Fersen. Ihre Spur führt nach Nordosten in die hügeligen Ödlande Eriadors. Amarthiúl, ein guter Freund Iârons, begleitet euch auf der Jagd.\n\nSchwierigkeit: Mittel\nEmpfohlene Charaktere: Dúnedain\nRegion: Eriador",
