evCallMorgulNazgulStory = "Niemand dient dem dunklen Herrscher besser as seine loyalsten Diener, die er einst mit den Ringen der Macht betrogen hat.",
evCallMumak = "Wahrgewordene Legende",
evCallMumakBattleStory = "Du blickst auf, als ein seltsames Horn ertönt. Was du siehst, lässt dir den Schreck in die Glieder fahren. Die Südländer führen einen mächtigen Mûmak aufs Schlachtfeld.",
evCallMumakInfo = "Eine mächtige Kreatur erscheint…",
evCallRivendellScout = "Späher aus Bruchtal",
evCallRivendellScoutInfo = "Rufe 1 COL_GREEN [i]Späher aus Imladris[/i] COL_DEF mit COL_ATTACK 2 COL_WILL 2 COL_HEALTH 2 COL_DEF herbei",
evCallRiverTroll = "Den Käfig öffnen",
evCallRiverTrollInfo = "Rufe 1 COL_ENEMY [i]Flusstroll[/i] COL_DEF herbei",
evCallRiverTrollStory = "In der Ecke stand ein verrosteter alter Käfig, in dessen Inneren es stockdunkel war. Als im Laufe der Kämpfe die Tür beschädigt wird, springt sie plötzlich auf und ein hässlicher Troll schleicht heraus. Kurz blinzelt er verwirrt, dann wird er euch gewahr und stützt sich in den Kampf.",
evCallRohan = "Verstärkung aus Edoras",
evCallRohanInfo = "Rufe 1 zufälligen Verbündeten aus [b][i]Rohan[/i][/b] herbei",
evCallRohanStory = "Aus Edoras, dem Sitz der Königshalle Rohans, kommt dringend nötige Verstärkung für euren Kampf.",
evCallSiegeRaft = "Sie kommen über den Fluss",
evCallSiegeRaftInfo = "Rufe 1 COL_ENEMY [i]Belagerungsfloß[/i] COL_DEF herbei",
evCallSiegeRaftStory = "Im Schutz der Nacht legt eine weitere schwimmende Plattform am Ostufer ab, um schwer bewaffnete Orks über den Fluss zu bringen.",
evCallSnowGiant = "Der Fels bewegt sich",
evCallSnowGiantInfo = "Rufe 1 COL_ENEMY [i]Schneeriesen[/i] COL_DEF herbei.",
evCallStrongBandit = "Feindliche Übermacht",
evCallStrongBanditInfo = "Rufe 1 COL_ENEMY [i]Groben Banditen[/i] COL_DEF herbei.",
evCallStrongBanditStory = "Die Banditen verstärken ihre Reihen und stellen euch mehr Gegner entgegen.",
evCallThief = "Auf sie, Jungs!",
evCallThiefInfo = "Rufe 2 COL_ENEMY [i]Taschendiebe[/i] COL_DEF herbei",
evCallUrukCommander = "Das Zeitalter der Menschen wird untergehen",
evCallUrukCommanderInfo = "Rufe 1 COL_BOSS [i]Hauptmann der Uruk-hai[/i] COL_DEF herbei",
evCallUrukCommanderStory = "Ein brutaler Ork erscheint, der offenbar Befehlsgewalt über die anderen Uruks hat und sie zu wütenderen Angriffen treibt.",
evCallWargs = "Verstärkung aus Isengart",
evCallWargsInfo = "Rufe 2 COL_ENEMY [i]Wargreiter der Uruk-hai[/i] COL_DEF herbei",
evCallWargsStory = "Isengart schickt zusätzliche Warge in den Kampf gegen uns.",
evCallWatcher = "Der Wächter erscheint",
evCallWatcherInfo = "Rufe den COL_BOSS [i]Wächter im Wasser[/i] COL_DEF herbei",
evCallWeaver = "Die Netze werden enger",
evCallWeaverInfo = "Rufe 1 COL_ENEMY [i]Weberin[/i] COL_DEF herbei",
evCallWeaverStory = "Eure Versuche, den ekligen Spinnennetzen zu entkommen, wird schwieriger, je mehr dieser fädenspinnenden Ungeheuer unermüdlich weitere Netze weben.",
evCallWidow = "Sie machen Jagd nach uns!",
evCallWidowInfo = "Rufe 1 COL_ENEMY [i]Jagende Witwe[/i] COL_DEF herbei",
evCallWidowStory = "Ihr versucht den grässlichen Spinnen zu entkommen, doch euch wird klar, dass sie euch nicht so leicht gehen lassen werden.",
evCallWoodelve = "Noch ein Wanderer…",
evCallWoodelveInfo = "Rufe 1 zufälligen [b][i]Waldelben[/i][/b]-Verbündeten herbei",
evCallWoodelveStory = "Plötzlich und unerwartet stößt ein Wanderer zu euch, der zufällig des Weges kam und nun mit euch in derselben Situation steckt.",
evCaveGas = "Höhlengas",
evCaveGasInfo = "Füge jeder Einheit 0-2 Schaden zu",
evCaveGasStory = "Einer deiner Gefährten bemerkt aufziehende Schwaden. Ehe ihr euch verseht, überkommt euch ein Hustenkrampf. Gas! Offenbar dringt es durch eine Felsspalte aus der Tiefe herauf.",
evCaveTorch = "Licht im Dunkeln",
evCaveTorchInfo = "Erhalte 1 [i]Höhlenfackel[/i], um [b]Finster[/b] von Gefahren zu entfernen",
evCDLabAdvance = "Strategisch vorgehen",
evCDLabAdvanceInfo = "Erhöht die Wahrscheinlichkeit, das COL_QUEST [i]Labyrinth der Verzweiflung[/i] COL_DEF beim nächsten Versuch zu verlassen",
evCDLabAdvanceStory = "Das Labyrinth im Inneren von Carn Dûm ist tückisch. Nach endlosem Umherirren findet man sich am selben Ort wieder, an dem man es betreten hat. Wenn ihr strategisch vorgeht und Wegweiser hinterlasst, könnt ihr das vielleicht von nun an vermeiden.",
evChallengeBoar = "Eberclan herausfordern",
evChallengeBoarInfo = "Beginne den Kampf gegen den COL_ENEMY [i]Häuptling des Eberclans[/i] COL_DEF. Dafür darf sich kein Gegner im Spiel befinden. Es können neue Gegner erscheinen und Sauron kehrt zurück ins Spiel, falls er gepasst hat.",
evChallengeBoarStory = "Ihr fordert den Eberclan heraus. Ihr Häuptling wird euch unermüdlich jagen und beansprucht eure Helme als Trophäe für seine beindruckende Sammlung.",
evChallengeRaven = "Rabenclan herausfordern",
evChallengeRavenInfo = "Beginne den Kampf gegen den COL_ENEMY [i]Häuptling des Rabenclans[/i] COL_DEF. Dafür darf sich kein Gegner im Spiel befinden. Es können neue Gegner erscheinen und Sauron kehrt zurück ins Spiel, falls er gepasst hat.",
evChallengeRavenStory = "Ihr fordert den Rabenclan heraus. Ihr Häuptling hat eine verdächtige Verbindung zu den schwarzen Rabenvögeln, die immer wieder über dem Kampfplatz kreisen, und es ist keinesfalls sicher, ob sie einen Kampf mit dem Clan weiterhin nur aus sicherer Entfernung beobachten.",
evChallengeWolf = "Wolfsclan herausfordern",
evChallengeWolfInfo = "Beginne den Kampf gegen den COL_ENEMY [i]Häuptling des Wolfclans[/i] COL_DEF. Dafür darf sich kein Gegner im Spiel befinden. Es können neue Gegner erscheinen und Sauron kehrt zurück ins Spiel, falls er gepasst hat.",
evChallengeWolfStory = "Ihr fordert den Wolfsclan heraus. Auch wenn der Blutpakt mit den Wargen gebrochen ist, bleibt er eine Herausforderung. Dieser Clan ist bekannt dafür, Wölfe zu domestizieren. Den Häuptling begleitet natürlich der größte von allen…",
evChooseBonus = "Unterstützung der Stadtbewohner",
evChooseBonusInfo = "Jeder Spieler wählt: +2 Ressourcen; oder ziehe 2 Karten",
evChooseBonusStory = "Obschon es eine Verschwörung mitten unter ihnen gibt, sind viele Stadtbewohner doch rechtschaffene Leute, die dich und deine Gefährten bereitwillig bei der Verbrechensbekämpfung unterstützen.",
evConcernedCitizen = "Besorgte Bürger",
evConcernedCitizenInfo = "Sauron ruft COL_QUEST [i]Besorgte Bürger[/i]COL_DEF herbei, wenn Gegner oder Zielvorgaben das Spiel verlassen und Sauron weniger als 3 Karten im Spiel hat.",
evConcernedCitizenStory = "Nach der Bekanntwerdung des Diebstahls ist Edoras in Aufruhr. Die Bürger sind misstrauisch und deine Nachforschungen werden sie sicherlich nicht beruhigen.",
evContraHuntingAruwethil = "Rückschlag",
evContraHuntingAruwethilInfo = "+1 Fortschritt auf COL_QUEST [i]Verfolge Arúwethil[/i]",
evConvinceBoar = "Überzeuge den Eberclan",
evConvinceBoarStory = "Der Eberclan-Häuptling, ein Berg von einem Mann, stürzt zu Boden, seine Waffe zerbrochen neben ihm. Die Krieger um euch herum halten inne und sehen ein, dass Widerstand zwecklos ist.",
evConvinceClanInfo = "-3 COL_THREAT Bedrohung COL_DEF. Lege alle Diener dieses Clans aus Saurons Hand und Deck ab. Du musst den Häuptling des Clans herausgefordert und besiegt haben.",
evConvinceRaven = "Überzeuge den Rabenclan",
evConvinceRavenStory = "Der Rabenhäuptling kämpft bis zum letzten Atemzug, bevor er schließlich unter eurer Klinge zusammenbricht. Seine Krieger verstummen, dann schallt das Krächzen der Raben durch die Lüfte, und der Clan beugt sich eurem Willen.",
evConvinceWolf = "Überzeuge den Wolfsclan",
evConvinceWolfStory = "Der stolze Anführer des Wolfsclans fällt auf die Knie und erkennt widerwillig eure Stärke an. Seine Krieger senken ihre Waffen und erklären sich bereit, eure Sache zu unterstützen",
evCramSupply = "Letzte Vorräte",
evCramSupplyInfo = "Jeder Spieler erhält COL_PURPLE [i]Cram[/i]",
evCrowHealth = "Große Schwärme",
evCrowHealthInfo = "+2 COL_HEALTH Gesundheit COL_DEF für jeden [i]Krähenschwarm[/i] an diesem Ort",
evCrowHealthStory = "Das Land zwischen der Pforte von Rohan und den Gebirgen Dunlands wird seit jeher von zwielichtigen Krähen bewohnt.",
evCrumblindTunnel = "Einstürzende Tunnel",
evCrumblindTunnelInfo = "+5 COL_WILL Willenskraft COL_DEF pro Spieler für COL_QUEST [i]Stollen freiräumen[/i] COL_DEF",
evCrumblindTunnelStory = "Ein plötzlicher Einsturz verschüttet weitere Teile des Tunnelnetzwerks und blockiert den Weg.",
evDamage3Hero = "Verderben",
evDamage3HeroInfo = "Füge 1 zufälligen Helden 3 Schaden zu",
evDamage3HeroStory = "Ihr weht euch tapfer gegen die Orks, doch die Bogenschützen der Orks sind eine zunehmende Gefahr. Obwohl sie schlecht zielen, kann ein einzelner glücklicher Pfeil jederzeit großes Unglück anrichten.",
evDamageAlly = "Pfeil aus dem Nichts",
evDamageAllyInfo = "Füge 1 zufälligen Verbündeten 2 Schaden zu",
evDamageCharNBInfo = "Füge 1 zufälligen Charakter 2 Schaden zu (ignoriert [b]Block[/b]",
evDamageNoEquipments = "Es trifft die Unvorbereiteten",
evDamageNoEquipmentsInfo = "Füge jedem Charakter ohne Verstärkung 2 Schaden zu (ignoriert [b]Block[/b] und [b]Heimlich[/b])",
evDamageNoEquipmentsStory = "Je länger sich deine Gruppe durch die lebensfeindliche Natur kämpfen muss, desto mehr zehrt das Wetter an euren Kräften. Wer nicht gut ausgerüstet ist, leidet umso mehr darunter.",
evDamageOnThreat = "Tödliche Furcht",
evDamageOnThreatInfo = "Wann immer die Bedrohung steigt, füge 1 zufälligen Charakter 1 Schaden zu (ignoriert [b]Block[/b])",
evDamageOnThreatStory = "Ihr seid aufgebrochen, um euch dem erstarkten Bösen zu stellen. Jetzt, da ihr es sehen und fühlen könnt, erwacht eine große Angst in euch.",
evDamagePerThreatEvent = "Verderbnis ausrotten",
evDamagePerThreatEventInfo = "Füge für jedes noch nicht ausgelöste Bedrohungsereignis 1 zufälligen Gegner 3 Schaden zu und reduziere die COL_THREAT Bedrohung COL_DEF um 3",
evDamagePerThreatEventStory = "Das Böse mag übermächtig erscheinen, doch mit Entschlossenheit und gutem Willen könnt ihr es bezwingen.",
evDamageTower = "Risse entdeckt",
evDamageTowerInfo = "Senke die COL_HEALTH Gesundheit COL_DEF von COL_BOSS [i]Dem Turm[/i] COL_DEF auf 1",
evDamageTwoMinions = "Schlag aus dem Hinterhalt",
evDamageTwoMinionsInfo = "Füge bis zu 2 Dienern jeweils 4 Schaden zu",
evDamageTwoMinionsStory = "Manche Gegner wirken zu stark, um sie in einem direkten Kampf zu bezwingen. Mit taktischer Rafinesse lässt sich dem beikommen.",
evDamageWillless = "Die Hoffnung schwindet",
evDamageWilllessInfo = "Füge jedem Charakter mit weniger als 2 COL_WILL Willenskraft COL_DEF 2 Schaden zu",
evDangerWillThreatReduction = "Keine Gefahr!",
evDangerWillThreatReductionInfo = "Das nächste Mal, wenn Sauron 1 Gefahr spielt, senke die COL_THREAT Bedrohung COL_DEF entsprechend ihres COL_WILL Willenskraftwertes COL_DEF. Es muss 1 [b][i]Zwerg[/i][/b] mit 2 COL_WILL Willenskraft COL_DEF oder mehr im Spiel sein.",
evDangerWillThreatReductionStory = "Manche deiner Gefährten erzittern angesichts der Dunkelheit, die euch hier unten begegnet, doch ein mutiger Begleiter setzt zu einer ergreifenden Rede an. Ihr spürt, wie die Worte euch neuen Glauben geben, auch den finstersten Gefahren widerstehen zu können.",
evDarkDangerWill = "Die Dunkelheit wächst",
evDarkDangerWillInfo = "+2 COL_WILL Willenskraftwert COL_DEF für alle [b]Finsteren[/b] Gefahren",
evDeadlyAccusation = "Bösartige Anschuldigungen",
evDeadlyAccusationInfo = "Rufe 2x COL_DANGER [i]Drohendes Unheil[/i] COL_DEF herbei",
evDeadsGateFree = "Wir brauchen eine Ablenkung!",
evDeadsGateFreeInfo = "Entferne die Einschränkung vom COL_QUEST [i]Tor der Toten[/i].COL_DEF ",
evDeadsGateFreeStory = "Je schneller ihr das Tor schließt, desto eher ebbt der Ansturm der Untoten ab. Doch der alte Mann stand euch im Weg und er war ein fürchterlicher Gegner. Iâron führte ein paar Männer zur Seite und versuchte, seine Aufmerksamkeit auf sich zu lenken, sodass ihr vielleicht zum Tor vordringen könnt.",
evDealHalfDamage = "Geführter Schlag",
evDealHalfDamageInfo = "Füge 1 Gegner Schaden entsprechend der Hälfte seiner COL_HEALTH Gesundheit COL_DEF zu (ignoriert [b]Block[/b])",
evDealHalfDamageStory = "Ihr springt vor und teilt einen Hieb in Richtung eines besonders mächtigen Feindes aus, darauf vertrauend, dass die Valar euren Arm leiten mögen",
evDefenseOsgiliathEast = "Den Osten verteidigen",
evDefenseOsgiliathEastInfo = "Beginne die Verteidigung im COL_QUEST [i]Ostviertel[/i]COL_DEF. Es dürfen sich keine Gegner oder Quests im Spiel befinden. Es können neue Gegner erscheinen und Sauron kehrt zurück ins Spiel, falls er gepasst hat.",
evDefenseOsgiliathEastStory = "Die Orks versuchen mit selbstgebauten Flößen über den Fluss zu setzen. Wir müssen sie aufhalten, ehe sie das Ufer erreichen!",
evDefenseOsgiliathNord = "Den Norden verteidigen",
evDefenseOsgiliathNordInfo = "Beginne die Verteidigung im COL_QUEST [i]Nordviertel[/i]COL_DEF. Es dürfen sich keine Gegner oder Quests im Spiel befinden. Es können neue Gegner erscheinen und Sauron kehrt zurück ins Spiel, falls er gepasst hat.",
evDefenseOsgiliathNordStory = "Ein mächtiger Heerführer Mordors befielt seinen Truppen einen Angriff auf den Norden der Stadt.",
evDefenseOsgiliathSouth = "Den Süden verteidigen",
evDefenseOsgiliathSouthInfo = "Beginne die Verteidigung im COL_QUEST [i]Südviertel[/i]COL_DEF. Es dürfen sich keine Gegner oder Quests im Spiel befinden. Es können neue Gegner erscheinen und Sauron kehrt zurück ins Spiel, falls er gepasst hat.",
evDefenseOsgiliathSouthStory = "Die Haradrim führen einen gewaltigen [i]Mûmak[/i] ins Feld, um die Stadt von Süden aus einzunehmen.",
evDefenseOsgiliathWest = "Den Westen verteidigen",
evDefenseOsgiliathWestInfo = "Beginne die Verteidigung im COL_QUEST [i]Westviertel[/i]COL_DEF. Es dürfen sich keine Gegner oder Quests im Spiel befinden. Es können neue Gegner erscheinen und Sauron kehr zurück ins Spiel, falls er gepasst hat.",
evDefenseOsgiliathWestStory = "Orks sind in den Westen der Stadt vorgedrungen und fallen über die Verteidiger her. Die Soldaten Gondors benötigen Unterstützung!",
evDefHope = "Moment der Klarheit",
evDefHopeInfo = "Jeder Spieler erhält eine zufällige Karte.",
evDefThreat1 = "Schwere Strapazen",
evDefThreat2 = "Saurons Zorn",
evDesperateAttack = "Verzweifelte Angriffe",
evDesperateAttackInfo = "Die ersten beiden [b][i]Banditen[/i][/b], die Sauron pro Runde spielt, erhalten [b]Drang[/b] und bringen 1 Ressource zurück.",
evDesperateAttackStory = "Die Banditen haben nichts mehr zu verlieren und verteidigen ihren Unterschlupf mit allem, was sie haben.",
evDeviceCallDamage = "Der Einfluss des Geräts",
evDeviceCallDamageInfo = "[b]Ende[/b]: Rufe 1 zufälligen [b][i]Rhudaur[/i][/b]-Gegner herbei. Füge jeder Einheit 1 Schaden zu (ignoriert [b]Block[/b])",
evDiscardAlliesFromHand = "Deutlich in der Unterzahl",
evDiscardAlliesFromHandInfo = "Lege alle Verbündeten aus der Hand jedes Spielers ab",
evDiscardAllOrcs = "Den Orks entwischen",
evDiscardAllOrcsInfo = "Lege alle Orks ab",
evDiscardAllOrcsStory = "Dir gelingt ein gewitztes Ablenkungsmaneuver, sodass ihr euch ungesehen in die Stadt schleichen könnt und die Orks draußen vergeblich nach euch suchen.",
evDiscardDanger = "Raus hier!",
evDiscardDangerInfo = "Lege 1 Gefahr ab. Das Ablegen löst keine [b]Rache[/b]-Effeke aus",
evDiscardEnemyShadow = "Weiche zurück!",
evDiscardEnemyShadowInfo = "Entferne 1 Schatten-Verstärkung von 1 Gegner",
evDiscardEnemyShadowStory = "Die Feinde werden von unnatürlichem Hass angetrieben, doch sie zeigen sich beeindruckt, als du dich ihnen mutig in den Weg stellst.",
evDiscardHand = "Fortgespült",
evDiscardHandAllyThreat = "Eine Ablenkung schaffen",
evDiscardHandAllyThreatInfo = "Lege 1 Verbündeten aus deiner Hand ab und senke die COL_THREAT Bedrohung COL_DEF entsprechend der Kosten der abgelegten Karte",
evDiscardHandAllyThreatStory = "Der Wald wimmelt von Feinden, die es schwierig machen, Gollums Spur zu folgen. Einer deiner Freunde schlägt vor, sie abzulenken, um dir etwas Zeit zu verschaffen.",
evDiscardHandInfo = "Jeder Spieler legt seine gesamte Hand ab",
evDiscardHandStory = "Eine gigantische Welle rollt heran, brandet über die Böschung und reißt dich von den Beinen. Als du das Gleichgewicht und die Orientierung wiedererlangt hast, musst du bestürzt mitansehen, wie dein Rucksack den Fluss hinuntertreibt und in den rauschenden Stromschnellen verschwindet.",
evDiscardPursuer = "Verfolger abschütteln",
evDiscardPursuerInfo = "Lege 1 Gegner ab. Es müssen sich mindestens 5 Gegner im Spiel befinden.",
evDiscardPursuerStory = "Von den Dúnedain hast du dir einige Tricks abgeschaut, wie man selbst hartnäckige Verfolger abschütteln kann.",
evDistractPatrol = "Die Patrouille ablenken",
evDistractPatrolInfo = "Sauron legt seine gesamte Hand ab",
evDoItTogether = "Nur gemeinsam seid ihr stark",
evDoItTogetherInfo = "Jeder Spieler erhält 2x COL_PURPLE [i]Gemeinsame Sache[/i]",
evDoubleLembas = "Elbengebäck",
evDoubleLembasInfo = "Erhalte 2 COL_GREEN [i]Lembas[/i] COL_DEF ",
evDoubleLembasStory = "Du hast ganz vergessen, dass du in Bruchtal nahrhaftes Elbenbrot eingepackt hast. Wo ist es nur geblieben?",
evDoubleThreat = "Drohende Dunkelheit",
evDoubleThreatInfo = "Jeglicher Zuwachs der COL_THREAT Bedrohung COL_DEF ist von nun an verdoppelt",
evDrawAndCost = "Teure Vorräte",
evDrawAndCostInfo = "Jeder Spieler zieht 1 Karte und erhöht deren Kosten um 1",
evDrawAndCostStory = "Eure Vorräte schrumpfen schnell, deshalb müsst ihr sie mit Bedacht einsetzen.",
evDrawReduction = "Verlaufen",
evDrawReductionGollumStory = "Links sind Bäume, rechts sind Bäume und dazwischen noch mehr Bäume.",
evDrawReductionInfo = "Reduziere das Ziehen von Karten in dieser Auffrischungsphase für jeden Spieler um 1",
evDrawReductionPearlsStory = "Das Gelände ist schwierig. Ihr müsst aufpassen, wohin Ihr tretet, und Eure Ausrüstung liegt schwer auf Eurem Rücken.",
evDruiadanOsgiliathStory = "Die Drúedain erweisen sich als treue Verbündete. Auf unseren Hilferuf hin schicken sie ein paar Krieger Richtung Osgiliath.",
evDunedainDeck = "Dúnedain eilen herbei",
evDunedainDeckInfo = "Füge dem Deck jedes Spielers 3 zufällige [b][i]Dúnedain[/i][/b]-Verbündete hinzu",
evDunedainDeckStory = "Zum Glück musst du diesen Abenteuer nicht mit deinen Freunde allein bestehen. Die Dúnedain zählen zu den fähigsten Kämpfern Mittelerdes.",
evDungeonGuard = "Wächter auf Kontrollgang",
evDungeonGuardInfo = "Rufe 1 COL_ENEMY [i]Zellenwächter[/i] COL_DEF herbei",
evDungeonGuardStory = "Amarthiúl schiebt dich in die Schatten, als ein Gefängniswärter um die Ecke biegt.",
evDunHealer = "Dúnedain-Heilmittel",
evDunHealerInfo = "Rufe 1 COL_GREEN [i]Heilerin der Dúnedain[/i] COL_DEF herbei und stelle 1 COL_HEALTH Gesundheit COL_DEF bei jedem Charakter wieder her",
evDunHealerStory = "Die Dúnedain kennen die heilsamen Wirkungen vieler Kräuter, doch wenige reichen an Athelas heran, auch Königskraut genannt. Einst wurde die Pflanze von Westernis nach Mittelerde mitgebracht, wo nur wenige ihre heilenden Eigenschaften kennen.",
evDunlendingRage = "Schrei der Dunländer",
evDunlendingRageInfo = "+1 COL_ATTACK Angriff COL_DEF für jeden [b][i]Dunländer[/i][/b], den Sauron in diese Runde ausspielt",
evDunlendingRageStory = "Die Dunländer stoßen grausame Kriegsschreie aus, die euch in den Knochen zittern lassen. Ihre Entschlossenheit, euch zu vernichten, wächst mit jedem Augenblick.",
evDunNoHeroWillTurn = "Gefrorene Hoffnung",
evDunNoHeroWillTurnStory = "Angesichts der Grausamkeit eurer Widersacher sackt euch für einen Moment das Herz unter die Gürtellinie.",
evDurinsDoor = "Glücklicher Einfall",
evDurinsDoorInfo = "Öffne die [i]Türen von Durin[/i]",
evDwarfHeroResources = "Jagd nach Mithril",
evDwarfHeroResourcesInfo = "+1 Ressource für jeden Spieler für jeden eigenen [i][b]Zwerg[/b][/i]-Helden im Spiel",
evDwarvenAxes = "Waffenständer",
evDwarvenAxesInfo = "Du erhältst 2 COL_RED [i]Zwergenäxte[/i]",
evDwarvenEnforcement = "Eskorte anfordern",
evDwarvenEnforcementInfo = "Füge dem Deck jedes Spielers 3 zufällige [b][i]Zwergen[/i][/b]-Verbündete hinzu. Es dürfen nicht mehr als 2 Verbündete im Spiel sein.",
evDwarvenEnforcementStory = "Ihr bittet König Dáin Eisenfuß, eine kleine Eskorte von Zwergenkrieger auszustatten, um euch in die bedrohlichen Tiefen des Erebor zu begleiten. Nach einigem Murren willigt der Zwergenkönig ein, doch die Krieger müssen erst ihre Ausrüstung zusammensuchen, ehe sie zu euch stoßen.",
evEagleWardenCall = "Rettung aus der Luft",
evEagleWardenCallInfo = "Rufe 1 COL_RED [i]Geflügelten Wächter[/i] COL_DEF herbei und aktiviere ihm bei seiner Ankunft [b]Schützen[/b]. Der Geflügelte Wächter hat COL_ATTACK 3 COL_WILL 0 COL_HEALTH 6 COL_DEF mit [b]Fernkampf[/b] und [b]Fliegend[/b]",
evEagleWardenCallStory = "Als euch die Verfolger schon beinahe umzingelt hatten, eilt plötzlich ein mächtiger Adler herbei, um euch aus der Situation zu retten.",
evEdorasHints = "Vertrauen der Königsfamilie",
evEdorasHintsInfo = "Jeder Spieler erhält eine Hinweiskarte.",
evEdorasHintsStory = "Ihr beweist eure Loyalität und Tapferkeit, wodurch ihr das Vertrauen der Königsfamilie gewinnt. Dadurch erhaltet ihr Zugang zu wertvollen Informationen über die Diebe und eine Spur zu deren Aufenthaltsort.",
evElrondsCouncil = "Elronds Rat",
evElrondsCouncilInfo = "Jeder Spieler zieht 2 Karten",
evElwingsFlight = "Hoffnung aus Geschichte",
evElwingsFlightInfo = "Erhalte COL_BLUE Elwings FluchtCOL_DEF, um COL_WILL Willenskraft COL_DEF wiederherzustellen",
evElwingsFlightStory = "Die Erinnerung an alte Geschichten kann Hoffnung in ausweglosen Situationen wiederbeleben. Die Legende von Elwing ist eine von ihnen. Um dem Angriff von Feanors Söhnen zu entkommen, stürzte sich die Gemahlin Earendils ins Meer und wurde von Ulmo gerettet. Gemeinsam mit Earendil und einem Silmaril segelte sie nach Valinor. Später heißt es, Elwing habe die Sprache der Seevögel erlernt.",
evEndlessUndead = "Endlose Horden",
evEndlessUndeadInfo = "Sauron erhält jedes Mal eine COL_ENEMY [i]Untote Horde[/i]COL_DEF, wenn eine COL_ENEMY [i]Untote Horde[/i] COL_DEF besiegt wird.",
evEndlessUndeadStory = "Die Untoten strömen in Scharen heran und drohen einfach über euch hinwegzuschwemmen.",
evEnemy2AttackMalus = "Auskundschaften",
evEnemy2AttackMalusInfo = "-2 COL_ATTACK Angriff COL_DEF für jeden Gegner in dieser Runde",
evEnemyHealAttackBonus = "Etwas Böses verleiht diesen Kreaturen Schnelligkeit",
evEnemyHealAttackBonusInfo = "Stelle bei jedem verwundeten Gegner 2 COL_HEALTH Gesundheit COL_DEF wieder her und verleihe ihm +1 COL_ATTACK Angriff COL_DEF ",
evEnemyHealAttackBonusStory = "Böse Mächte sind hier am Werk, sie machen eure Feinde stark und richten ihren Willen gegen euch.",
evEnemyMoreHealth = "Erstarkende Feinde",
evEnemyMoreHealthInfo = "+2 COL_HEALTH Gesundheit COL_DEF für jeden Gegner",
evEnemyMoreHealthStory = "Das schlechte Wetter macht euch schwer zu schaffen. Die Kreaturen, welche es auf euch abgesehen haben, scheinen es hingegen zu genießen.",
evEntDraught = "Wasser des Lebens",
evEntDraughtInfo = "Erhalte 1 COL_GREEN [i]Ent-Trunk[/i] COL_DEF (es muss ein [b][i]Ent[/i][/b]-Held im Spiel sein).",
evEntDraughtStory = "Der Ent-Trunk dient den Ents als Nahrung. Er stärkt und verjüngt den Körper … und befreit die Rinde von altem Moos.",
evEquipRandomWeapon = "Waffenfund",
evEquipRandomWeaponInfo = "Rüste 1 Charakter mit einer zufälligen [b][i]Waffe[/i][/b] aus",
evEquipRandomWeaponStory = "Als ihr in einer kleinen Höhle Zuflucht vor dem Regen sucht, entdeckt einer deiner Begleiter das Skelett eines Wanderers. Für ihn kommt jede Hilfe zu spät, doch neben ihm findet ihr eine Waffe, die euch vielleicht noch von Nutzen sein könnte.",
evEquipResources = "Waffen für den Kampf",
evEquipResourcesInfo = "+1 Ressource für jeden Spieler pro eigenem Charakter mit mindestens 1 Verstärkung",
evEquipTorch = "Lasst uns etwas Licht entzünden",
evEquipTorchInfo = "Jeder Spieler kann 1 Charakter mit der Spezial-Verstärkung [i]Höhlenfackel[/i] ausrüsten, um [b]Finster[/b] von Gefahren zu entfernen",
evEquipTwoWarAxes = "Geschenk der Clans",
evEquipTwoWarAxesInfo = "Rüste 2 Charaktere ohne [b][i]Rüstung[/i][/b] mit einer COL_RED [i]Kriegsaxt[/i] COL_DEF auf. Die COL_RED [i]Kriegsaxt[/i] COL_DEF verleiht ihnen COL_ATTACK +2 Angriff COL_DEF und entfernt [b]Fernkampf[/b]",
evEquipTwoWarAxesStory = "Ihr habt die Dunländer überzeugt, das Richtige zu tun. Auch wenn sie ihr Hügelgrab nicht selbst entweihen können, geben sie euch bereitweillig ein paar Waffen, mit denen euch die bevorstehenden Kämpfe leichter fallen dürften.",
evEreborSmith = "Inbetriebnahme",
evEreborSmithInfo = "Rufe 1 COL_RED [i]Erebor-Hammerschmied[/i] COL_DEF herbei. Du musst die Schmiede repariert haben.",
evEreborSmithStory = "Sobald ihr die Schmiede repariert habt, könnt ihr einen erfahrenen Schmied aus den oberen Etagen herbeuholen, um euch für die anstehende Expedition in die Tiefe auszurüsten.",
evEreborTorch = "Es ist dunkel hier unten",
evEreborTorchStory = "Unter den wiederbesiedelten Tunneln des Erebor lauert die Dunkelheit. Ohne Licht, seid ihr hier unten verloren.",
evEreborTunnelTorch = "Ein Licht im Dunkeln",
evEreborTunnelTorchStory = "Zündet eine Fackel an, wenn ihr euch in der tiefen Dunkelheit unter dem Berg nicht verirren wollt.",
evExhaustedAllies = "Kräftezehrende Reise",
evExhaustedAlliesInfo = "Erschöpfe jeden Verbündeten",
evExhaustedAlliesStory = "Die Strapazen des rauen Landes zehren an den Kräften deiner Begleiter, sodass ihr eine Pause einlegen müsst.",
evExhaustFangornNoEntHero = "Verwurzelt!",
evExhaustFangornNoEntHeroInfo = "Erschöpfe 1 zufälligen Helden, der kein [b][i]Ent[/i][/b] ist. Er kann diese Runde nicht spielbereit gemacht werden.",
evExhaustFangornNoEntHeroStory = "Einer deiner Gefährten war unachtsam. Da griffen die umstehenden Bäume plötzlich mit ihren Wurzeln nach ihm und sperrten ihn in einem holzigen Käfig ein.",
evExhaustSouthrons = "Aus dem Hinterhalt!",
evExhaustSouthronsInfo = "Du greifst aus dem Hinterhalt an. Alle Gegner sind erschöpft.",
evExhaustTwoUndead = "Die Willenlosen überlisten",
evExhaustTwoUndeadInfo = "Erschöpfe 2 [b][i]Untote[/i][/b]",
evExhaustTwoUndeadStory = "Die Untoten waren zwar zahlreich, aber es fehlte ihnen an Intelligenz. Mit Geschick könnt ihr sie vielleicht überlisten.",
evExhaustTwoWolfs = "Mit Feuer vertreiben",
evExhaustTwoWolfsInfo = "Erschöpfe 2 [b][i]Wolf[/i][/b]-Gegner",
evExhaustTwoWolfsStory = "Die Wölfe ziehen ihre Kreise immer enger um deine Gruppe. Du blickst in ihre hungrigen Augen und siehst sogar ihre lechzenden Fratzen im Halbdunkel. Da springt einer deiner Gefährten vor, fuchtelt wild mit einem brennenden Holzscheid und vertreibt die Ungeheuer für den Moment in die Dunkelheit.",
evExpensiveDraw = "Feindseliger Wald",
evExpensiveDrawInfo = "+1 Kosten für jede Karte, die die Spieler von nun an ziehen",
evExpensiveDrawStory = "Das Gestrüpp wird dichter, die Bäume rücken enger zusammen. Dornen und Wurzeln behindern euren Weg. Es wird zusehends schwieriger, voranzukommen.",
evExpensiveEnemyRes = "Mächtige Gegner",
evExpensiveEnemyResInfo = "+1 Ressource für Sauron, wann immer er einen Gegner spielt, der 5 oder mehr kostet",
evExpensiveEnemyResStory = "Trolle und Riesen durchstreifen das Land, immer auf der Suche nach Futter. Man geht ihnen besser aus dem Weg, wenn man kann.",
evFangornProgress = "Den Wald wachrütteln",
evFangornProgressInfo = "Wende pro Spieler 2 Fortschritt auf COL_QUEST [i]Fangorn erwacht[/i] COL_DEF an.",
evFangornProgressStory = "Der Fangorn ist ein alter Wald, in dem die mächtigen Baumhirten wohnen. Sie scheren sich nicht viel um die Belange der Menschen, doch wenn ihnen jemand klarmacht, welche Bedrohung die Äxte der Orks auch für ihr Reich darstellt, würden sie vielleicht einschreiten.",
evFangornTrap = "Falle vorbereiten",
evFangornTrapInfo = "Erhalte 1 COL_GREEN [i]Falle im Wald[/i]COL_DEF.",
evFangornTrapStory = "Der Wald mag gefährlich sein, doch mit Geschick könnt ihr ihn auch für euren Vorteil nutzen.",
evFearAlliesHopeMalus = "Was, wenn sie noch einen holen?",
evFearAlliesHopeMalusInfo = "+1 COL_THREAT Bedrohung COL_DEF für jeden Verbündeten mit weniger als 2 COL_WILL Willenskraft COL_DEF ",
evFearAlliesHopeMalusStory = "Das Verschwinden eures Freundes hat einige von euch eingeschüchtert. Sollte ihn jemand aus Beorns Halle entführt haben, wer sagt dann, dass sie nicht noch jemanden mitnehmen?",
evFetchedFromHorse = "Vom Pferd geholt",
evFetchedFromHorseStory = "Im Schlachtgetümmel scheut dein Pferd, wirft dich ab und stürmt mit deiner Ausrüstung davon.",
evFillUndead = "Man kann sie nicht töten",
evFillUndeadInfo = "Fülle Saurons Reihe mit [b][i]Untoten[/i][/b]",
evFillUndeadStory = "Tapfer kämpft ihr euch durch die Reihen der Feinde im Inneren der dunklen Festung. Doch hoffnungslos erscheint euer Vorhaben, als sich ein Untoter nach dem anderen erhebt.",
evFindHeroCell = "Kerker absuchen",
evFindHeroCellInfo = "Suche nach weiteren Zellen, in denen Helden eingesperrt sind.\nRufe 1 COL_QUEST [i]Kerkerzelle[/i] COL_DEF oder 1 COL_QUEST [i]Folterzelle[/i] COL_DEF herbei. Es darf keine solche Zelle im Spiel sein und Saurons Reihe darf nicht voll sein.",
evFindHeroCellStory = "Gemeinsam mit Amarthiúl schleichst du möglichst lautlos durch den Kerker von Berg Gram auf der Suche nach weiteren Gefängniszellen, in denen deine Freunde eingesperrt sind.",
evFindHiddenStair = "Klapptür im Boden",
evFindHiddenStairInfo = "Rufe 1 COL_DANGER [i]Verborgene Treppe[/i] COL_DEF herbei. Sie hat [b]Vergänglich[/b] und führt bei Erreichen zu einem verborgenen Artefakt.",
evFindHiddenStairStory = "Als du durch einen finsteren Gang schleichst, bleibst du mit dem Fuß an etwas hängen. Tastend stellst du fest, dass es eine Klapptür im Boden ist, unter der sich eine geheime Treppe verbirgt. Wo sie wohl hinführt?",
evFindMoriaWay = "Immer der Nase nach",
evFindMoriaWayInfo = "Wende pro Spieler 2 Fortschritt auf COL_QUEST [i]Der Weg durch Moria[/i] COL_DEF an. Es darf keine Gefahr und kein Gegner im Spiel sein.",
evFindMoriaWayStory = "\"Und im Zweifelsfalle, Meriadoc, sollte man immer seiner Nase folgen.\"",
evFlamingLog = "Feuer entzünden",
evFlamingLogInfo = "Erhalte 1 [i]Flammenden Scheit[/i]: ([b][i]Waffe[/i][/b] mit +1 COL_ATTACK Angriff COL_DEF beim Angriff auf [b][i]Untote[/i][/b] und +1 COL_WILL Willenskraft COL_DEF beim Angehen von Gefahren",
evFogFromBarrows = "Nebel der Hügelgräber",
evFogFromBarrowsInfo = "Erschöpfe 1 zufälligen Helden. Er kann diese Runde nicht spielbereit gemacht werden",
evForestTrap = "In die Falle locken",
evForestTrapInfo = "Erhalte 1 COL_GREEN [i]Falle im Wald[/i] COL_DEF ",
evForestTrapStory = "Die Dúnedain bereiten eine Falle vor, um die Orks im Chetwald abzufangen.",
evForGondor = "Für Gondor!",
evForGondorInfo = "Jeder Spieler erhält 1x COL_PURPLE [i]Für Gondor![/i] COL_DEF : +1 COL_ATTACK Angriff COL_DEF für jeden Charakter und [b]Block[/b] für jeden [b][i]Gondor[/i][/b]-Charakter in dieser Runde",
evForGondorStory = "Im Angesicht der feindlichen Übermacht reckst du dein Schwert in die Höhe und treibst deine Gefährten zu neuer Entschlossenheit an.",
evFornostAlly = "Entschlossene Waldläufer",
evFornostAllyInfo = "Lege 1 zufälligen Verbündeten aus deiner Hand ab und erhalte 1 COL_RED [i]Rächer von Fornost[/i] COL_DEF mit Kosten von 1",
evFornostAllyStory = "Fornost Erain diente den Dúnedain als Versammlungsstätte bei wichtigen Festen, darum waren sie sehr entschlossen, die Untoten zurück ins Grab zu schicken.",
evFramsTombDamage = "Frams Fluch",
evFramsTombDamageInfo = "COL_QUEST [i]Das verfluchte Grab[/i] COL_DEF erhält [b]Ende[/b]: Füge 1 zufälligen Charakter 1 Schaden zu (ignoriert [b]Block[/b])",
evFramsTombDamageStory = "Diese Gruft ist kein Ort, wo Lebende sich aufhalten sollten.",
evGapInShieldwall = "Schwäche im Schildwall",
evGapInShieldwallInfo = "Entferne für diese Runde [b]Block[/b] und [b]Abschirmen[/b] von allen COL_BOSS [i]Wächtern[/i] COL_DEF im Spiel",
evGapInShieldwallStory = "Durch einen gekonnten Angriff auf eine Schwachstelle im Schildwall der Wächter gelingt es euch, ihre Verteidigung zu durchbrechen. Schlagt zu, solange sie verwundbarer sind.",
evGleamingSplendor = "Bringt ihnen das Licht!",
evGleamingSplendorInfo = "Erhalte COL_BLUE [i]Gleißende Pracht[/i] COL_DEF, um die feindliche Verteidigung zu brechen und die Schatten zu enthüllen",
evGollumHunter = "Wilde Jagd",
evGollumHunterInfo = "Rufe in jeder Auffrischung weitere COL_ENEMY [i]Jäger aus Mordor[/i] COL_DEF abhängig von der Spielerzahl herbei, solange du COL_QUEST [i]Gollums Spur[/i] COL_DEF verfolgst.",
evGondorDefender = "Verstärkung",
evGondorDefenderInfo = "Rufe 1 zufälligen Verbündeten aus [b][i]Gondor[/i][/b] herbei",
evGondorDefenderStory = "Im hitzigen Kampfgefecht eilt ein Soldat Gondors zu dir und stellt sich unter deinen Befehl.",
evGoodPowers = "Es gibt etwas Gutes in der Welt",
evGoodPowersInfo = "Stiehl 3 Ressourcen von Sauron",
evGoodSupplies = "Ausreichend Proviant",
evGoodSuppliesInfo = "Jeder Spieler erhält +2 Ressourcen und zieht 1 Karte",
evGramAlarm = "Alarm!",
evGramAlarmInfo = "Du löst den Alarm aus.",
evGramAlarmStory = "Die Bemühungen, deine Helden unbemerkt zu befreien, sind fehlgeschlagen. In der Nähe verkünden Trommelschläge und laute Rufe, dass die Orks dich entdeckt haben.",
evGramPrison = "Im Kerker von Berg Gram",
evGramPrisonInfo = "Du bist auf dich gestellt, bis du das COL_QUEST [i]Unbeaufsichtigte Tor[/i] COL_DEF geöffnet hast. Sauron kommt erst ins Spiel, wenn der Alarm ausgelöst wird.",
evGramPrisonStory = "Deine Gefährten sind im Kerker gefangen, befreie sie! Amarthiúl hat es irgendwie geschafft, einen Weg in den Kerker zu finden. Nun müsst ihr euch in den dunklen Gängen auf euer Können verlassen, bis ihr einen Weg findet, Hilfe zu holen.",
evGrantBlock = "Beherzte Verteidigung",
evGrantBlockInfo = "Verleihe jedem Charakter in dieser Runde [b]Block[/b]",
evGrantBlockStory = "Ihr ruft eure Gefährten zusammen und stellt euch Rücken an Rücken, um die Angriffe der Feinde besser abwehren zu können.",
evGreenWillBonus = "Alter Wald, altes Wissen",
evGreenWillBonusInfo = "+1 COL_WILL Willenskraft COL_DEF für jeden Charakter der COL_GREEN Wissens-COL_DEF Sphäre im Spiel.",
evGreenWillBonusStory = "Der heutige Fangorn ist ein Überrest der großen Wälder aus dem Ersten Zeitalter. In jedem Winkel ist sein Alter spürbar. Wenn man genau hinhört, kann man die Bäume wispern hören.",
evGuardiansStrongerRecall = "Ewige Wächter",
evGuardiansStrongerRecallInfo = "Verdoppele die COL_HEALTH Gesundheit COL_DEF aller COL_BOSS [i]Wächter[/i] COL_DEF, die neu ins Spiel kommen.",
evGuardiansStrongerRecallStory = "Ihr ringt die Wächter mit aller Kraft nieder, doch zu eurer Überraschung stehen sie wieder auf. Diese Krieger scheinen durch eine unerschöpfliche Entschlossenheit angetrieben zu sein, die sie trotz schwerster Wunden immer wieder auf die Beine zwingt. Es ist, als ob ihre Pflicht zum Schutz des Hügelgrabs sie unbesiegbar macht.",
evGuardThreeOwnChars = "Osgiliaths Wacht",
evGuardThreeOwnCharsInfo = "Aktiviere [b]Schützen[/b] bei bis zu 3 deiner Charaktere",
evGuardThreeOwnCharsStory = "Wir wussten, dass der Angriff der Feinde unerbittlich sein würde. Deshalb mussten wir unsere Verteidigungspositionen gut vorbereiten.",
evHailofArrows = "Sendet einen Pfeilhagel",
evHailofArrowsInfo = "Jeder [b]Fernkampf[/b]-Charakter fügt 1 zufälligen Gegner 2 Schaden zu",
evHailofArrowsStory = "Eure Bogenschützen nehmen die verwundbarsten Feinde ins Visier und überziehen sie mit einem Pfeilhagel.",
evHandAllyProgress = "Um Hilfe rufen",
evHandAllyProgressInfo = "Wende für jeden Verbündeten auf der Hand der Spieler 1 Fortschritt auf die aktuelle Quest an.",
evHandAllyProgressStory = "Ihr seid verloren und verlassen im Herzen des Fangorn. Schreit um Hilfe und hofft, dass die Ents euch hören!",
evHandCostReduction = "Mit wenig zurechtkommen",
evHandCostReductionInfo = "-1 Kosten für jede Karte auf der Hand der Spieler (mindestens 1). Du musst einen [b][i]Zwerg[/i][/b]-Helden kontrollieren.",
evHandCostReductionStory = "Die Zwerge haben gelernt, unter dem Berg mit dem wenigen auszukommen, das sie bei sich führen können.",
evHealAllEnemies = "Gefährliche Geschäfte",
evHealAllEnemiesInfo = "Stelle die COL_HEALTH Gesundheit COL_DEF bei allen Gegnern vollständig wieder her",
evHealAllEnemiesSnailStory = "Der eklige Schleim der riesigen Schnecke scheint die Kreaturen ihre Wunden vergessen zu lassen.",
evHealAllies2 = "Erfrischendes Wasser",
evHealAllies2Info = "Stelle bei jedem Verbündeten 2 COL_HEALTH Gesunndheit COL_DEF wieder her",
evHealAllies2Story = "Nach unzähligen, zähen Stunden im klammen Dunkel des Düsterwalds stellt der Große Fluss von Wilderland einen überaus willkommenen Anblick dar. Obwohl euch Orks auf der Fährte sind, entscheidest du, dass eine kurze Rast angebracht ist.",
evHealByWill = "Wir können später bluten",
evHealByWillInfo = "Stelle bei jedem Charakter COL_HEALTH Gesundheit COL_DEF in Höhe seiner COL_WILL Willenskraft COL_DEF wieder her",
evHealByWillStory = "Wenn ein verletzter Mann nicht weiterkämpft, wird er vielleicht nie wieder dazu kommen.",
evHealEnemyAttackers = "Bestialischer Rausch",
evHealEnemyAttackersInfo = "Gegner stellen nun jedes Mal 1 COL_HEALTH Gesundheit COL_DEF wieder her, wenn sie angreifen",
evHealEnemyAttackersStory = "Deine Feinde werden von unbändigem Hass getrieben und verfallen bei der Jagd nach dir in einen ungeheuerlichen Rausch.",
evHealHeros = "Hilfe aus Bree",
evHealHerosInfo = "Stelle bei jedem Helden 2 COL_HEALTH Gesundheit COL_DEF wieder her",
evHealingHerbs = "Heilende Kräuter",
evHealingHerbsInfo = "Stelle bei bis zu 3 Charakteren bis zu 2 COL_HEALTH Gesundheit COL_DEF wieder her",
evHealingHerbsStory = "Am Wegesrand findet ihr einige Kräuter, deren heilende Wirkung euch bekannt ist. Ihr verteilt sie an diejenigen unter euch, die sie am dringendsten benötigen.",
evHealWolfEnd = "Kochendes Blut",
evHealWolfEndInfo = "Stelle am Ende dieser Runde die COL_HEALTH Gesundheit COL_DEF aller [b][i]Wölfe[/i][/b] vollständig wieder her",
evHealWolfEndStory = "Das Blut der Bestien ermöglicht ihnen rasche Regernation. Verwundungen reichen nicht aus, ihr müsst sie töten.",
evHeroHealth = "Ork-Arznei",
evHeroHealthInfo = "+1–3 COL_HEALTH Gesundheit COL_DEF für jeden Helden",
evHeroHealthStory = "Bei einer Orkleiche findet ihr ein durchsichtiges Fläschchen, das erstaunlicherweise heil geblieben ist. Diese Ork-Arznei schmeckt und riecht zwar abscheulich, dafür hat sie eine belebende Wirkung.",
evHeroicHealth = "Heroische Ausdauer",
evHeroicHealthInfo = "+3 COL_HEALTH Gesundheit COL_DEF für jeden einzigartigen Charakter",
evHeroMassAttack = "Heroischer Angriff",
evHeroMassAttackInfo = "Erschöpfe 1 Helden mit mindestens 2 COL_ATTACK Angriff COL_DEF und füge jedem Gegner Schaden entsprechend der Gegnerzahl zu",
evHeroPermaWillMalus = "Mentale Strapazen",
evHeroPermaWillMalusInfo = "Dauerhaft -1 COL_WILL Willenskraft COL_DEF für jeden Helden",
evHeroPermaWillMalusStory = "Die Verfolgung zerrt an den Kräften. Nicht nur an den körperlichen, sondern in erster Linie auch an der Willensstärke deiner Gefährten.",
evHeroResources = "Jagd nach Vorräten",
evHeroResourcesInfo = "+1 Ressource für jeden Spieler für jeden eigenen Helden im Spiel",
evHeroResourcesStory = "In einem freien Moment schaut ihr euch in dem dunklen Raum um und entdeckt einige nützliche Dinge, die ihr verwenden könnt.",
evHeroSurgeManouver = "Koordiniertes Manöver",
evHeroSurgeManouverInfo = "Mache 2 Helden spielbereit und verleihe ihnen für diese Runde COL_ATTACK +1 Angriff COL_DEF. Wann immer sie diese Runde einen Angriff durchführen, erhält ihr Besitzer [b]Drang[/b].",
evHeroSurgeManouverStory = "Durch eine perfekte Abstimmung untereinander setzt ihr zu einem koordinierten Angriff an. Euer entschlossener Vorstoß bringt Morcarach in Bedrängnis und ihr nutzt die Gelegenheit, um erneut zuzuschlagen.",
evHeroTempWillRed = "Geflüster des Todes",
evHeroTempWillRedInfo = "-1 COL_WILL Willenskraft COL_DEF in dieser Runde für alle Helden",
evHeroTempWillRedStory = "Eine unheimliche Stimme durchdringt die Dunkelheit, und eure Herzen werden von einem unbehaglichen Gefühl der Verzweiflung ergriffen. Der Wille zu kämpfen schwindet, und Zweifel nagen an eurem Mut.",
evHiddenAttack = "Von hinten",
evHiddenAttackInfo = "Verleihe 1 spielbereiten Charakter [b]Heimlich[/b] und +2 COL_ATTACK Angriff COL_DEF für diese Runde",
evHiddenAttackStory = "Die Orks sind nicht sehr wachsam. Vielleicht kann sich einer aus eurer Gruppe von hinten anschleichen und sie überraschen?",
evHiddenMountainPath = "Versteckter Bergpfad",
evHiddenMountainPathInfo = "Wende 1 Fortschritt auf [i]Spur ins Gebirge[/i] an",
evHiddenMountainPathStory = "Einer deiner Gefährten entdeckt einen schmalen Bergpfad, auf dem noch deutlich die Fußspuren der Dunländer zu sehen sind. Vielleicht führt er euch an euer Ziel?",
evHiddenTrap = "Versteckte Grube",
evHiddenTrapInfo = "Erschöpfe 1 zufälligen Helden pro Spieler und füge ihm 2 Schaden zu",
evHideArwen = "Verbergen",
evHideArwenInfo = "Verleihe [i]Arwen[/i] [b]Heimlich[/b], bis sie eine Aktion durchführt.",
evHiredThugs = "Angeheurte Schläger",
evHiredThugsInfo = "Rufe 2 zufällige [b][i]Banditen[/i][/b] herbei",
evHitSpiderLeg = "Ab das Bein!",
evHitSpiderLegInfo = "Füge 1 [b][i]Spinne[/i][/b] 3 Schaden zu, entferne [b]Block[/b] und gib ihr -2 COL_ATTACK Angriff COL_DEF ",
evHitSpiderLegStory = "Mit einem glücklichen Streich trennt ihr einer der Kreaturen eines der vorderen Beine ab. Zwar haben sie viel zu viele Gliedmaßen, doch es wird sie entscheidend schwächen.",
evHopeInDarknes = "Hoffnung im Dunkeln",
evHopeInDarknesInfo = "+1 COL_ATTACK Angriff COL_DEF und +1 COL_WILL Willenskraft COL_DEF für jeden unverwundeten Charakter sowie +2 COL_HEALTH Gesundheit COL_DEF für jeden verwundeten Charakter",
evHopeLost = "Schatten kriechen hervor",
evHopeLostInfo = "Reduziere den Schicksalsgrad auf 0",
evHopeLostStory = "Die Schatten über den Hügeln werden dichter, und ein unheilvolles Flüstern erreicht eure Ohren. Es ist, als ob eine unsichtbare Macht euren Anstrengungen trotzt.",
evHotOil = "Siedendes Öl",
evHotOilInfo = "Besiege 1 Diener ohne [b]Fernkampf[/b]",
evHotOilStory = "Die Verteidiger schütten siedend heißes Öl über die Angreifer am Tor, das den sicheren Tod bedeutet.",
evHuntingArtefact = "Zurückgeklaut!",
