evUndeadHealthInfo = "+2 COL_HEALTH Gesundheit COL_DEF für jeden [b][i]Untoten[/i][/b] im Spiel",
evUndeadHealthStory = "Es muss eine alte, finstere Macht am Werke sein, welche die Untoten zäher werden lässt. Es wird immer schwerer, sie niederzustrecken.",
