evUngolHopeDamageInfo = "Füge COL_BOSS [i]Ungoliants Brut[/i] COL_DEF 5 Schaden zu",
evUngolHopeDamageStory = "Die Spinne ist zäh und Verwundungen scheinen ihr wenig anzuhaben. Die Unterseite ihres Körpers aber ist weniger geschützt. Ein gezielter Stich könnte ihr arg zusetzen.",
