bonusDori = "Füge 1 Helden Doris Angriffwert hinzu",
powerBofur = "Ziehe 1 Waffe aus deinem Deck",
discardAllyFromDeck = "Lege 1 Verbündeten aus deinem Deck ab",
campIceplain = "Spuren im Eis",
campIceplainInfo = "Nach dem Ausbleiben einer wichtigen Handelskarawane entsendet der Zwergenkönig unter dem Erebor eine Gruppe tapferer Helden in die eisige Wildnis des Nordens. Ihre Aufgabe: das Schicksal der Vermissten aufklären – koste es, was es wolle.\nTagelang kämpfen sich die Gefährten durch beißenden Wind und kniehohen Schnee. Schließlich tauchen am Horizont zerschlissene Zeltplanen und rauchgeschwärzte Vorratskisten auf: ein Lager, zerstört von Gewalt. Inmitten der weiten, schutzlosen Ebene sind die Helden der Kälte ausgeliefert – und nicht allein. Feinde lauern im Schneesturm, und uralte Gefahren erwachen unter dem Eis.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Zwerge\nRegion: Eisland",
missionIceplain1 = "Verlorene Karawane",
missionIceplain1Goal = "Durchsuche das verwüstete Lager und verfolge die Spuren der Vermissten.",
missionIceplain1Info = "Im Schneesturm stoßt ihr auf die Überreste eines verwüsteten Zwergenlagers. Noch während ihr euch einen Überblick verschafft, greifen Orks an, die das Lager geplündert haben. Ihr müsst das Lager durchsuchen und den Spuren möglicher Überlebender folgen.",
missionIceplain2 = "Das Verlies",
missionIceplain2Goal = "Dringe in das Orklager ein und befreie die gefangenen Zwerge.",
missionIceplain2Info = "Die Spuren führen euch in eine von Eis überzogene Höhle – das Versteck einer Orkgruppe. In ihrem Inneren werden die vermissten Zwerge gefangen gehalten. Ihr müsst euch durchschlagen und sie lebend befreien.",
missionIceplain3 = "Letzter Ausweg",
missionIceplain3Goal = "Halte die angreifende Horde auf und besiege alle Feinde, um zu entkommen.",
missionIceplain3Info = "Kaum ist die Rettung gelungen, bricht die Orkhorde über euch herein. Die Helden stehen mit dem Rücken zur Wand – der einzige Weg hinaus führt durch den Ansturm. Es gilt, standzuhalten und alle Feinde zu vernichten.",
evIceplainThreat1 = "Kälte in den Gliedern",
evIceplainThreat1Info = "Füge jedem Charakter ohne [b]Block[/b] 1 Schaden zu.",
evIceplainThreat1Story = "Die klirrende Kälte schleicht sich in Knochen und Muskeln. Bewegung wird zur Qual, und Stöhnen wird laut, als die Schwächsten straucheln.",
evIceplainThreat2 = "Panik im Trupp",
evIceplainThreat2Info = "+1 COL_THREAT Bedrohung COL_DEF pro Spieler; oder 1 zufälliger Verbündeter verlässt das Spiel.",
evIceplainThreat2Story = "Unruhe macht sich breit. Stimmen werden laut, Blicke nervös. Ein unachtsamer Moment reicht – und einer der Gefährten stürzt sich kopflos in den Tod.",
evIceplainThreat3 = "Schwäche durch Kälte",
evIceplainThreat3Info = "Lege die Waffe eines zufälligen Helden ab.",
evIceplainThreat3Story = "Die Finger sind steif, der Griff wird schwächer. Im nächsten Moment reißt ein plötzlicher Angriff die Waffe aus der Hand – und der Held steht wehrlos da.",
evIceplainHope1 = "Stärkung aus der Ferne",
evIceplainHope1Info = "Jeder Spieler erhält 2 Ressourcen.",
evIceplainHope1Story = "Ein Bote trifft mit Vorräten ein – unerwartet, aber dringend gebraucht. Rasch verteilt ihr die Ressourcen auf alle Gefährten.",
evIceplainHope2 = "Chaos der Diener",
evIceplainHope2Info = "Jeder Diener fügt einem zufälligen Gegner 1 Schaden zu (ignoriert [b]Block[/b]). Es darf kein Schurke im Spiel sein.",
evIceplainHope2Story = "Führungslos verfallen die Reihen der Orks in Chaos, bis sie gegenseitig aufeinander einschlagen.",
evIceplainHope3 = "Unerwartete Störung",
evIceplainHope3Info = "Verdopple die Kosten von Saurons aktuellen Handkarten.",
evIceplainHope3Story = "Ein Beben erschüttert das feindliche Lager. Der Einfluss der Dunkelheit schwankt – die Orks zögern, als ihre finsteren Pläne ins Wanken geraten.",
evIceplainM1Hope1 = "Überlebender der Karawane",
evIceplainM1Hope1Info = "Erhalte einen zufälligen nicht-einzigartigen [b][i]Zwergen[/i][/b]-Verbündeten.",
evIceplainM1Hope1Story = "Zwischen umgestürzten Wagen und eingefrorenen Vorräten entdeckt ihr in einer Schneemulde einen verletzten Zwerg – einen Überlebenden der überfallenen Karawane. Er berichtet, dass sene Begleiter entführt wurden.",
evIceplainM1Threat1 = "Sturmfront",
evIceplainM1Threat1Info = "Diese Runde erleidet jeder Charakter 1 Schaden, wenn er eine Zielvorgabe angeht.",
evIceplainM1Threat1Story = "Ein plötzlich aufziehender Schneesturm erschwert jede Bewegung. Wer sich nach vorne wagt, wird von schneidenden Eiskristallen gezeichnet.",
evIceplainM1Threat2 = "Verwehung",
evIceplainM1Threat2Info = "Entferne allen Fortschritt von der aktuellen Quest.",
evIceplainM1Threat2Story = "Einsetzender Schneefall verschüttet eure Spuren und Markierungen. Alles, was ihr erreicht hattet, scheint mit einer Schicht aus Eis und Wind verweht zu sein.",
evIceplainM2Hope1 = "Gerechter Zorn",
evIceplainM2Hope1Info = "Diese Runde erhalten alle Helden [b]Drang[/b], wenn sie einen Schurken angreifen.",
evIceplainM2Hope1Story = "Der Anblick des Folterers und seiner grausamen Werkzeuge entfacht Entschlossenheit in euren Herzen. Eure Helden greifen mit einem Ziel an: diesem Wahnsinn ein Ende zu setzen.",
evIceplainM3Hope1 = "Flucht sichern",
evIceplainM3Hope1Info = "Erschöpfe alle Gegner im Spiel.",
evIceplainM3Hope1Story = "Während ihr euren Rückzug aus der Orkhöhle plant, löst einer der Gefährten einen Steinschlag aus. Die herabfallenden Felsen zwingen alle Feinde kurzzeitig in die Deckung.",
locationCompleted = "Ort abgeschlossen",
autoTravel = "Du reist am Ende der Runde automatisch weiter.",
campOrcSurprise = "Zwergenzwist",
campOrcSurpriseInfo = "Der Zwergenkönig entsendet euch in eine abgelegene Siedlung am Erebor. Zwischen mehreren Zwergenfamilien ist ein alter Streit neu entbrannt; Anschuldigungen, verletzte Ehre und gegenseitiges Misstrauen drohen die Gemeinschaft zu spalten. Ihr sollt zwischen ihnen vermitteln und die Streitenden versöhnen, ehe aus Worten Waffen werden.\n\nSchwierigkeit: Schwer\nEmpfohlene Charaktere: Zwerge\nRegion: Erebor",
missionOrcSurprise1 = "Zwist in der Siedlung",
missionOrcSurprise1Goal = "Schlichte den Streit, ehe die Bedrohung 40 erreicht.",
missionOrcSurprise1Info = "In der Siedlung stehen sich mehrere Zwergenfamilien unversöhnlich gegenüber. Anschuldigungen, verletzte Ehre und alte Rechnungen haben den Streit so weit eskalieren lassen, dass niemand mehr zuhört. Beruhigt die Streithähne, bevor aus dem Zwist ein offener Zwergenkrieg wird. Wird ein Wütender Zwerg besiegt, steigt die Bedrohung um 1.",
missionOrcSurprise2 = "Ansturm der Belagerer",
missionOrcSurprise2Goal = "Überstehe den zeitbeschränkten Ansturm der Belagerer. Solange er im Spiel ist, bleibt das Kriegslager gesperrt. Danach dürft ihr das Kriegslager bereits angehen, bevor ihr am Ende der Runde weiterreist.",
missionOrcSurprise2Info = "Kaum gelingt es euch, die Zwergenfamilien an einen Tisch zu bringen, ertönen vor der Siedlung Kriegshörner. Orks stürmen die äußeren Befestigungen, während ihr noch zwischen umgeworfenen Tischen und gezogenen Äxten steht. Haltet die erste Angriffswelle auf. Das außerhalb gelegene Kriegslager versorgt Sauron während jeder Auffrischung mit billigeren Dienern.",
missionOrcSurprise3 = "Durbnâkhs Kriegslager",
missionOrcSurprise3Goal = "Löse das Kriegslager auf und besiege Durbnâkh. Ihr könnt beide Ziele in beliebiger Reihenfolge erfüllen.",
missionOrcSurprise3Info = "Ihr verfolgt die zurückweichenden Orks bis zu ihrem befestigten Lager. Dort erwartet euch Durbnâkh, ein standhafter Wargführer, der seine Krieger immer wieder in den Kampf treibt. Entscheidet selbst, ob ihr zuerst die Befestigungen brecht oder den Anführer ausschaltet – doch erst wenn Lager und Boss gefallen sind, ist die Siedlung gerettet.",
evOrcSurpriseClearHead = "Ein klarer Kopf",
evOrcSurpriseClearHeadInfo = "-2 COL_THREAT Bedrohung COL_DEF.",
evOrcSurpriseClearHeadStory = "Für einen Augenblick weichen Lärm und Zorn. Ihr erkennt, was wirklich auf dem Spiel steht, und gewinnt neue Zuversicht.",
evOrcSurpriseSupplies = "Zwergische Versorgung",
evOrcSurpriseSuppliesInfo = "Jeder Spieler stellt bei 1 eigenen Charakter bis zu 2 COL_HEALTH Gesundheit COL_DEF wieder her.",
evOrcSurpriseSuppliesStory = "Zwischen Werkstätten und Vorratskammern finden sich Verbände, stärkendes Bier und alles, was erschöpfte Kämpfer wieder auf die Beine bringt.",
evOrcSurpriseForErebor = "Für Erebor!",
evOrcSurpriseForEreborInfo = "Diese Runde erhalten alle Helden +1 COL_ATTACK Angriff COL_DEF und [b]Block[/b].",
evOrcSurpriseForEreborStory = "Der gemeinsame Ruf hallt zwischen den Felsen wider. Für einen Moment kämpft ihr wie eine einzige, unerschütterliche Schildmauer.",
evOrcSurpriseUnrest = "Unruhe in den Reihen",
evOrcSurpriseUnrestInfo = "Jeder Spieler erschöpft einen zufälligen spielbereiten Charakter.",
evOrcSurpriseUnrestStory = "Befehle gehen im Lärm unter, Zweifel greifen um sich, und selbst erfahrene Gefährten verlieren kostbare Augenblicke.",
evOrcSurpriseTalkDown = "Gut zureden",
evOrcSurpriseTalkDownInfo = "Erschöpfe 1 spielbereiten [b][i]Wütenden Zwerg[/i][/b].",
evOrcSurpriseTalkDownStory = "Mit Geduld, Nachdruck und dem richtigen Hinweis auf die gemeinsamen Interessen bringt ihr einen der Streithähne wenigstens vorübergehend zum Schweigen.",
evOrcSurpriseGetHelp = "Hilfe holen",
evOrcSurpriseGetHelpInfo = "Rufe in der nächsten Auffrischung pro Spieler 1 zufälligen nicht-einzigartigen Verbündeten herbei.",
evOrcSurpriseGetHelpStory = "Einige Bewohner verlassen unauffällig den Saal. Beim nächsten Aufbruch kehren sie mit hilfsbereiten Freunden und Verwandten zurück.",
evOrcSurpriseConvincedDwarf = "Ein überzeugter Zwerg füllt die Lücke",
evOrcSurpriseConvincedDwarfInfo = "Diese Runde: Wird ein eigener Verbündeter besiegt, ruft der betroffene Spieler 1 zufälligen nicht-einzigartigen [b][i]Zwergen[/i][/b]-Verbündeten herbei. Höchstens einmal pro Spieler.",
evOrcSurpriseConvincedDwarfStory = "Einige der versöhnten Zwerge sind euch bis zum Kriegslager gefolgt. Fällt einer eurer Gefährten, tritt einer von ihnen entschlossen an seine Stelle.",
evOrcSurpriseDwarfWar = "Zwergenkrieg",
evOrcSurpriseDwarfWarInfo = "Die Bedrohung hat 40 erreicht. Die Mission ist verloren.",
evOrcSurpriseDwarfWarStory = "Der letzte Rest von Vernunft zerbricht. Äxte werden gezogen, Familienbanner erhoben – aus dem Streit ist ein Krieg geworden.",
evOrcSurpriseArmory = "Waffenkammer öffnen",
evOrcSurpriseArmoryInfo = "Jeder Spieler rüstet einen eigenen Helden ohne Waffe mit einer COL_RED [i]Zwergenaxt[/i] COL_DEF und einen eigenen Helden ohne Rüstung mit einem COL_RED [i]Rundschild[/i] COL_DEF aus.",
evOrcSurpriseArmoryStory = "Die versöhnten Familien öffnen gemeinsam die Waffenkammer. Was eben noch gegeneinander gerichtet war, dient nun der Verteidigung der Siedlung.",
evOrcSurpriseCommonEnemy = "Ein gemeinsamer Feind",
evOrcSurpriseCommonEnemyInfo = "Jeder Spieler erhält 2 zufällige nicht-einzigartige [b][i]Zwergen[/i][/b]-Verbündete. Ihre Kosten werden auf 0 gesetzt.",
evOrcSurpriseCommonEnemyStory = "Der Angriff der Orks beendet jeden Zwist. Aus allen Gassen strömen bewaffnete Zwerge herbei und stellen sich ohne Zögern an eure Seite.",
evOrcSurpriseEscalation = "Der Angriff eskaliert",
evOrcSurpriseEscalationInfo = "Setze die Bedrohung auf 35, falls sie niedriger ist.",
evOrcSurpriseEscalationStory = "Mit einem Mal brechen Orks an mehreren Stellen zugleich durch. Die vermeintlich begrenzte Attacke entpuppt sich als vorbereiteter Großangriff.",
evOrcSurpriseBreach = "Die Bresche hält nicht",
evOrcSurpriseBreachInfo = "Rufe pro Spieler 1 zufälligen COL_ENEMY [i]Festungsstürmer[/i]COL_DEF, COL_ENEMY [i]Ork-Brandstifter[/i] COL_DEF oder COL_ENEMY [i]Ork-Armbrustschützen[/i] COL_DEF herbei, höchstens 3 Gegner.",
evOrcSurpriseBreachStory = "Unter Haken, Feuer und Bolzen bricht ein weiterer Abschnitt der Verteidigung zusammen. Neue Angreifer ergießen sich durch die Bresche.",
evOrcSurpriseRockslide = "Kontrollierter Felssturz",
evOrcSurpriseRockslideInfo = "Wähle bis zu 3 spielbereite Gegner. Erschöpfe sie und füge jedem zufällig 2–3 Schaden zu.",
evOrcSurpriseRockslideStory = "Mit gezielten Schlägen löst ihr oberhalb des Lagers Geröll. Die Felsen treffen nicht jeden Feind gleich hart, doch sie bringen den Angriff ins Stocken.",
evOrcSurpriseSpearTraps = "Speerfallen",
evOrcSurpriseSpearTrapsInfo = "Für den Rest der Mission erleidet COL_BOSS [i]Durbnâkh[/i] COL_DEF nach jedem seiner Angriffe 3 Schaden.",
evOrcSurpriseSpearTrapsStory = "Zwergische Speere werden zwischen den Felsen verborgen. Wann immer Durbnâkh zum Angriff prescht, gerät sein Warg in eine neue Falle.",
evOrcSurpriseBarricades = "Neue Barrikaden",
evOrcSurpriseBarricadesInfo = "Entferne allen Fortschritt von COL_QUEST [i]Kriegslager[/i]COL_DEF.",
evOrcSurpriseBarricadesStory = "Während ihr an einer Flanke vorankommt, errichten die Orks hinter euch neue Wälle aus Pfählen, Schilden und Geröll.",
evOrcSurpriseHuntingCall = "Durbnâkhs Jagdruf",
evOrcSurpriseHuntingCallInfo = "Solange COL_BOSS [i]Durbnâkh[/i] COL_DEF im Spiel ist, erhält jeder Diener während seiner Auffrischung dauerhaft +1 Gesundheit.",
evOrcSurpriseHuntingCallStory = "Durbnâkhs Ruf fährt durch das Lager. Jeder Ork richtet sich höher auf, jeder Warg schnappt nach der Leine – und mit jeder neuen Angriffswelle werden sie zäher.",
evOrcSurpriseRelentless = "Unerbittliche Angriffe",
evOrcSurpriseRelentlessInfo = "Diese Runde erhalten alle Gegner mit dem Trait [b][i]Ork[/i][/b] oder [b][i]Wolf[/i][/b] [b]Standhaft[/b].",
evOrcSurpriseRelentlessStory = "Durbnâkhs Krieger werfen sich ohne Rücksicht auf Verluste erneut in den Kampf. Kaum weicht ein Feind zurück, greift er schon wieder an.",
