evStrongerDangers = "Growing Danger",
evStrongerDangersInfo = "+1 COL_WILL Willpower COL_DEF for all Hazards from now on",
evStrongerDangersStory = "The evil is growing stronger and more powerful by the moment if you don't put a stop to it.",
evTargetedObstruction = "Targeted Obstruction",
evTargetedObstructionInfo = "+2 COL_WILL Willpower COL_DEF for all Hazards in this location.",
evTargetedObstructionStory = "The bandits are increasing their security and setting traps along the way to the camp. This will probably make the pursuit more difficult.",
