evThreatMinusEnemiesStory = "With every foe downed, Middle-earth will become a little safer and peace may be restored to Framsburg.",
evThreatMinusEnemy = "Hold on!",
evThreatMinusEnemyInfo = "-5 COL_THREAT threat COL_DEF. The value is reduced by 1 for each enemy in play.",
evThreatMinusEnemyStory = "The soldiers of Gondor are used to being the bulwark of the free peoples against the rising might of Mordor.",
