evThreatQuestsStory = "Even if you try to keep quiet, the orcs are beginning to notice that something is going on in the mountain.",
evTortureAttackMalus = "Disarmed",
evTortureAttackMalusInfo = "The Orcs have taken your weapons from you. Each character is reduced to 1 COL_ATTACK Attack COL_DEF until you recover your weapons.",
evTortureWeaponsBack = "Recover Weapons",
evTortureWeaponsBackInfo = "You find the weapons that the orcs took from you. Any attack penalty from the missing weapons is removed.",
evTreacheryCostReduction = "Treacherous Secrets",
evTreacheryCostReductionInfo = "The cost of each [b][i]treachery[/i][/b] on Sauron's Hand is reduced to 0",
evTreasureChamber = "Secret Chamber",
evTreasureChamberInfo = "Each player gains 1 random attachement. Reduce their cost to 0.",
evTrollRaft = "Distract the troll",
evTrollRaftInfo = "Remove the restriction from COL_QUEST [i]Board the Raft[/i]COL_DEF.",
evTrollRaftStory = "The troll crouches in the shadow of a rock overhang, where it probably wants to build a nest. It blocks the path you were about to take. 'What's that behind you?' you call to the troll.\nThat It's a pretty cheap trick, but then again, trolls aren't known for their cleverness.",
evTunnelDigger = "Diggers to work!",
evTunnelDiggerInfo = "Apply progress equal to the number of [b][i]Dwarf[/i][/b] Allies in play to COL_QUEST [i]Clear the Tunnels[/i] COL_DEF",
evTunnelDiggerStory = "Any dwarf can be a miner if needed.",
evTurnBandit = "Defector",
evTurnBanditInfo = "Discard 1 random [b][i]Bandit[/i][/b] and get 1 COL_GREY [i]Purified Bandit[/i]COL_DEF ",
evTurnBandits = "Convince the bandits",
evTurnBanditsInfo = "Discard each [b][i]Bandit[/i][/b] and gain 1 [i]Purged Bandit[/i] for each",
evTurnBanditStory = "Not every bandit is a criminal through and through. Some still have a sense of honor - and with the right words you might be able to win them over to your side.",
evTurnOrcsIntoWights = "Overrun by Fiends",
evTurnOrcsIntoWightsInfo = "Turn each [b][i]Orc[/i][/b] into a [b][i]Undead[/i][/b]",
evTurnOrcsIntoWightsStory = "Whatever the Orcs seek in Framsburg, they will be struck down by the multitude of fiends. But where an Orc once stood, there now rises a walking mountain of bones.",
evTwoEvents = "Bold Strategy",
evTwoEventsInfo = "Gain events with a cost of 2 until you have 5 cards in hand",
evTwoEventsStory = "In the face of the greatest danger, you have dug deep into your knowledge and skills and emerged stronger. Your experience and cunning have unlocked extraordinary tactical possibilities that will decisively influence the outcome of the battles ahead.",
evUndeadHealth = "Dark Sorcery",
evUndeadHealthInfo = "+2 COL_HEALTH Health COL_DEF for each [b][i]Undead[/i][/b] in play",
evUndeadHealthStory = "There must be some ancient, sinister force at work that is making the tougher. They're getting harder and harder to slay.",
evUngolHopeDamage = "Stab in the abdomen",
evUngolHopeDamageInfo = "Deal 5 damage to COL_BOSS [i]Ungoliants Spawn[/i]",
evUngolHopeDamageStory = "The spider is tough and seems unaffected by wounds, but the underside of its body is less protected. A well-placed sting could damage it.",
evUngolHopeExhaust = "Build a Trap",
evUngolHopeExhaustInfo = "Exhaust COL_BOSS [i]Ungoliants Spawn[/i]COL_DEF ",
evUngolHopeExhaustStory = "It is dangerous to approach the giant spider. To fight it, you may be able to take advantage of the environment and trap it.",
evUngolThreatHeal = "Disgusting Swarm",
evUngolThreatHealInfo = "Restore COL_BOSS [i]Ungoliants Swarm[/i] COL_DEF to full COL_HEALTH Health COL_DEF ",
evUngolThreatHealStory = "You are horrified as the giant spider eats the carcasses of smaller ones and gains new strength.",
