evWeakenGorknakhInfo = "-2 COL_ATTACK Attack COL_DEF for COL_BOSS [i]Gorknákh[/i]COL_DEF ",
evWeakenGorknakhStory = "As the giant lunges at you, you land a well-aimed jab under his armpits, causing him to fall back roaring. Hopefully he can't hit as hard from now on.",
