evWeakOrcHealthBonusInfo = "Orcs with 3 COL_HEALTH Health COL_DEF or less gain +1 COL_HEALTH Health COL_DEF upon arrival.",
evWeakOrcHealthBonusStory = "After killing the first orcs, you find that the rest are tougher in health and harder to kill.",
