evWolfGrillInfo = "Defeat 1 [b][i]Wolf[/i][/b] Minion and restore 2 COL_HEALTH Health COL_DEF to 1 Character",
evWolfGrillStory = "You valiantly defend yourself with weapons and fire. What's wrong with grilling already singed meat?",
evWolfThreat = "Wolves come and go",
evWolfThreatInfo = "+1 COL_THREAT Threat COL_DEF whenever a [b][i]Wolf[/i][/b] comes into play this round. -1 COL_THREAT Threat COL_DEF whenever a [b][i]Wolf[/i][/b] leaves play this round. You cannot activate this after Sauron has passed.",
