evWoodElfHopeInfo = "All [b][i]Wood Elves[/i][/b] gain +1 COL_WILL Willpower COL_DEF ",
evWoodElfHopeStory = "Once Mirkwood was called by the Elves Eryn Galen, Green Wood. Though the gloom has spread to the south, it is still a rightful part of the Wood Elf realm, and there are many encouraging songs about it.",
