evZeroEventsInfo = "Gain events with a cost of 0 until you have 5 cards in hand",
evZeroEventsStory = "Your journey has taken you through harsh and unforgiving lands, yet with each step, you learn new tactics and tricks that will aid you in the duels to come. Small successes and gained insights merge into a new, albeit simple, strategy.",
