campIceplain = "Tracks in the Ice",
campIceplainInfo = "After a vital dwarven caravan goes missing, the King under the Mountain dispatches a band of brave heroes into the frozen wilderness of the far North. Their mission: uncover the fate of the missing traders – no matter the cost.\nFor days, the companions trudge through biting winds and knee-deep snow. At last, torn tents and scorched supply crates rise into view on the horizon: a camp, ravaged by violence. Exposed on the open plain, the heroes are at the mercy of the cold – and they are not alone. Foes prowl within the snowstorm, and ancient dangers stir beneath the ice.\n\nDifficulty: Hard\nRecommended Characters: Dwarves\nRegion: Iceplain",
missionIceplain1 = "Lost Caravan",
missionIceplain1Goal = "Search the devastated camp and follow the trail of the missing dwarves.",
missionIceplain1Info = "In the midst of a blizzard, you discover the remains of a dwarven camp. As you investigate the wreckage, lurking orcs strike. Secure the area and follow the tracks leading away from the destruction.",
missionIceplain2 = "The Lair",
missionIceplain2Goal = "Enter the orc lair and rescue the captured dwarves.",
missionIceplain2Info = "The trail leads into an ice-covered cave – the hideout of a brutal orc warband. Within, the missing dwarves are held captive. You must fight your way through and get them out alive.",
missionIceplain3 = "Last Escape",
missionIceplain3Goal = "Hold off the attacking horde and defeat all enemies to escape.",
missionIceplain3Info = "Just as the rescue succeeds, the orc horde launches a full assault. The heroes are cornered – the only path to freedom leads through the enemy ranks. Stand firm and wipe them out to escape the depths.",
evIceplainThreat1 = "Cold in the Limbs",
evIceplainThreat1Info = "Deal 1 damage to each character without b]Block[/b].",
evIceplainThreat1Story = "The biting cold creeps into bones and muscles. Movement becomes agony, and groans rise as the weakest among you begin to falter.",
evIceplainThreat2 = "Panic in the Ranks",
evIceplainThreat2Info = "+1 COL_THREAT Threat COL_DEF per player; or 1 random ally leaves play.",
evIceplainThreat2Story = "Tension spreads. Voices rise, glances grow nervous. A single careless moment is enough – one companion bolts blindly to their doom.",
evIceplainThreat3 = "Weakness from the Cold",
evIceplainThreat3Info = "Discard the weapon of a random Hero.",
evIceplainThreat3Story = "Fingers stiffen, the grip weakens. In the blink of an eye, an ambush tears the weapon away – and the hero is left defenseless.",
evIceplainHope1 = "Support from Afar",
evIceplainHope1Info = "Each player gains 2 resources.",
evIceplainHope1Story = "A messenger arrives with supplies – unexpected, yet desperately needed. You quickly distribute the resources among your companions.",
evIceplainHope2 = "Servant Chaos",
evIceplainHope2Info = "Each Minion deals 1 damage to a random Enemy (ignores [b]Block[/b]). No Villain may be in play.",
evIceplainHope2Story = "Deprived of leadership, the ranks of orcs descend into chaos, turning against each other in violent confusion.",
evIceplainHope3 = "Unexpected Disruption",
evIceplainHope3Info = "Double the cost of Sauron's current hand cards.",
evIceplainHope3Story = "A tremor shakes the enemy camp. The power of darkness falters – the orcs hesitate as their sinister plans begin to unravel.",
evIceplainM1Hope1 = "Survivor of the Caravan",
evIceplainM1Hope1Info = "Gain a random non-unique [b][i]Dwarven[/i][/b] Ally.",
evIceplainM1Hope1Story = "Amid toppled wagons and frozen supplies, you find a wounded dwarf curled up in a snow hollow – the last survivor of the ambushed caravan.",
evIceplainM1Threat1 = "Snowstorm",
evIceplainM1Threat1Info = "This round, each Character that engages a Quest suffers 1 damage.",
evIceplainM1Threat1Story = "A sudden snowstorm makes every step a struggle. Those who push forward are cut and battered by swirling ice crystals.",
evIceplainM1Threat2 = "Snowdrift",
evIceplainM1Threat2Info = "Remove all progress from the current Quest.",
evIceplainM1Threat2Story = "Heavy snowfall buries your tracks and markers. All progress made so far vanishes beneath a layer of ice and wind.",
evIceplainM2Hope1 = "Righteous Fury",
evIceplainM2Hope1Info = "This round, all Heroes gain [b]Rush[/b] when attacking a Villain.",
evIceplainM2Hope1Story = "The sight of the Torturer and his cruel tools sparks fury in your hearts. Your heroes strike with one goal: to end his reign of pain.",
evIceplainM3Hope1 = "Securing the Escape",
evIceplainM3Hope1Info = "Exhaust all Enemies in play.",
evIceplainM3Hope1Story = "As you plan your retreat from the orc cave, one of your companions triggers a rockslide. Falling debris forces all enemies to take cover.",
locationCompleted = "Location completed",
autoTravel = "You automatically travel on at the end of the round.",
campOrcSurprise = "Dwarven Feud",
campOrcSurpriseInfo = "The Dwarf-king sends you to a remote settlement beneath Erebor. An old dispute has flared up again between several dwarven families; accusations, wounded pride, and mutual distrust threaten to divide the community. You are to mediate between them and reconcile the quarrellers before words give way to weapons.\n\nDifficulty: Hard\nRecommended Characters: Dwarves\nRegion: Erebor",
missionOrcSurprise1 = "Discord in the Settlement",
missionOrcSurprise1Goal = "Settle the dispute before Threat reaches 40.",
missionOrcSurprise1Info = "Several dwarven families in the settlement face each other in bitter hostility. Accusations, wounded pride, and old grievances have escalated so far that no one will listen. Calm the quarrellers before the dispute becomes an open dwarven war. Whenever an Enraged Dwarf is defeated, raise Threat by 1.",
missionOrcSurprise2 = "Onslaught of the Besiegers",
missionOrcSurprise2Goal = "Survive the Timed Onslaught of the Besiegers. While it is in play, the War Camp remains Locked. Afterwards, you may already engage the War Camp before travelling at the end of the round.",
missionOrcSurprise2Info = "No sooner have you brought the dwarven families to one table than war horns sound outside the settlement. Orcs storm the outer defenses while overturned tables and drawn axes still fill the hall. Hold back the first assault. During every Refresh, the camp beyond the walls makes Sauron's Minions cheaper.",
missionOrcSurprise3 = "Durbnâkh's War Camp",
missionOrcSurprise3Goal = "Resolve the War Camp and defeat Durbnâkh. You may complete these objectives in either order.",
missionOrcSurprise3Info = "You pursue the retreating orcs to their fortified camp. Durbnâkh awaits you there, a Steadfast warg leader who drives his warriors back into battle again and again. Decide whether to break the defenses first or strike down their leader – the settlement is safe only when both camp and boss have fallen.",
evOrcSurpriseClearHead = "A Clear Head",
evOrcSurpriseClearHeadInfo = "-2 COL_THREAT Threat COL_DEF.",
evOrcSurpriseClearHeadStory = "For a moment, anger and noise recede. You see what is truly at stake and regain your confidence.",
evOrcSurpriseSupplies = "Dwarven Supplies",
evOrcSurpriseSuppliesInfo = "Each player restores up to 2 COL_HEALTH Health COL_DEF to 1 Character they control.",
evOrcSurpriseSuppliesStory = "Workshops and storerooms provide bandages, strengthening ale, and everything weary fighters need to stand again.",
evOrcSurpriseForErebor = "For Erebor!",
evOrcSurpriseForEreborInfo = "This round, all Heroes gain +1 COL_ATTACK Attack COL_DEF and [b]Block[/b].",
evOrcSurpriseForEreborStory = "The common cry echoes between the rocks. For a moment, you fight as one unbreakable shield wall.",
evOrcSurpriseUnrest = "Unrest in the Ranks",
evOrcSurpriseUnrestInfo = "Each player exhausts a random ready Character.",
evOrcSurpriseUnrestStory = "Orders vanish in the din, doubt spreads, and even seasoned companions lose precious moments.",
evOrcSurpriseTalkDown = "Talk Them Down",
evOrcSurpriseTalkDownInfo = "Exhaust 1 ready [b][i]Enraged Dwarf[/i][/b].",
evOrcSurpriseTalkDownStory = "With patience, firmness, and a timely reminder of their common interests, you silence one quarreller for a while.",
evOrcSurpriseGetHelp = "Fetch Help",
evOrcSurpriseGetHelpInfo = "During the next Refresh, summon 1 random non-unique Ally per player.",
evOrcSurpriseGetHelpStory = "Several residents quietly leave the hall. At the next muster, they return with helpful friends and relatives.",
evOrcSurpriseConvincedDwarf = "A Reconciled Dwarf Fills the Gap",
evOrcSurpriseConvincedDwarfInfo = "This round: When an Ally controlled by a player is defeated, that player summons 1 random non-unique [b][i]Dwarven[/i][/b] Ally. At most once per player.",
evOrcSurpriseConvincedDwarfStory = "Some of the reconciled dwarves have followed you to the war camp. When one of your companions falls, one of them resolutely steps into the breach.",
evOrcSurpriseDwarfWar = "Dwarven War",
evOrcSurpriseDwarfWarInfo = "Threat has reached 40. The mission is lost.",
evOrcSurpriseDwarfWarStory = "The last restraint shatters. Axes are drawn and family banners raised – the dispute has become a war.",
evOrcSurpriseArmory = "Open the Armory",
evOrcSurpriseArmoryInfo = "Each player equips a Hero they control without a Weapon with a COL_RED [i]Dwarven Axe[/i] COL_DEF and a Hero they control without Armor with a COL_RED [i]Round Shield[/i]COL_DEF.",
evOrcSurpriseArmoryStory = "The reconciled families open the armory together. Weapons that moments ago faced each other now defend the settlement.",
evOrcSurpriseCommonEnemy = "A Common Enemy",
evOrcSurpriseCommonEnemyInfo = "Each player gains 2 random non-unique [b][i]Dwarven[/i][/b] Allies. Set their costs to 0.",
evOrcSurpriseCommonEnemyStory = "The orc assault ends every feud. Armed dwarves pour from every alley and take their place at your side without hesitation.",
evOrcSurpriseEscalation = "The Assault Escalates",
evOrcSurpriseEscalationInfo = "Set Threat to 35 if it is lower.",
evOrcSurpriseEscalationStory = "Orcs break through at several points at once. What seemed a limited raid reveals itself as a prepared major assault.",
evOrcSurpriseBreach = "The Breach Will Not Hold",
evOrcSurpriseBreachInfo = "Summon 1 random COL_ENEMY [i]Fortress Stormer[/i]COL_DEF, COL_ENEMY [i]Orc Arsonist[/i]COL_DEF, or COL_ENEMY [i]Orc Crossbowmen[/i] COL_DEF per player, up to 3 Enemies.",
evOrcSurpriseBreachStory = "Hooks, fire, and bolts tear down another section of the defenses. Fresh attackers pour through the breach.",
evOrcSurpriseRockslide = "Controlled Rockslide",
evOrcSurpriseRockslideInfo = "Choose up to 3 ready Enemies. Exhaust them and deal a random 2–3 damage to each.",
evOrcSurpriseRockslideStory = "Careful blows loosen the scree above the camp. The rocks do not strike every foe equally, but they bring the assault to a halt.",
evOrcSurpriseSpearTraps = "Spear Traps",
evOrcSurpriseSpearTrapsInfo = "For the rest of the mission, COL_BOSS [i]Durbnâkh[/i] COL_DEF suffers 3 damage after each of his attacks.",
evOrcSurpriseSpearTrapsStory = "Dwarven spears lie hidden between the rocks. Whenever Durbnâkh charges, his warg runs into another trap.",
evOrcSurpriseBarricades = "New Barricades",
evOrcSurpriseBarricadesInfo = "Remove all progress from COL_QUEST [i]War Camp[/i]COL_DEF.",
evOrcSurpriseBarricadesStory = "While you advance on one flank, the orcs raise new walls of stakes, shields, and rubble behind you.",
evOrcSurpriseHuntingCall = "Durbnâkh's Hunting Call",
evOrcSurpriseHuntingCallInfo = "While COL_BOSS [i]Durbnâkh[/i] COL_DEF is in play, every Minion permanently gains +1 Health during its Refresh.",
evOrcSurpriseHuntingCallStory = "Durbnâkh's call rolls through the camp. Every orc stands taller, every warg strains at its leash – and with each new assault they grow tougher.",
evOrcSurpriseRelentless = "Relentless Attacks",
evOrcSurpriseRelentlessInfo = "This round, all Enemies with the [b][i]Orc[/i][/b] or [b][i]Wolf[/i][/b] trait gain [b]Steadfast[/b].",
evOrcSurpriseRelentlessStory = "Durbnâkh's warriors hurl themselves back into battle without regard for losses. No sooner does one foe retreat than it attacks again.",
